SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is a diamagnetic substance?", "explanation": "Bismuth (Bi) is a classic diamagnetic substance. Diamagnetic materials have all electrons paired, leading to a small negative susceptibility (χ < 0). They are weakly repelled by a magnetic field. Aluminium is paramagnetic, iron and cobalt are ferromagnetic.", "correct_answer": "C", "concept_tags": ["diamagnetic-materials", "examples", "magnetic-classification"], "payload": {"question_id": "cuet-phy-magmat-materials-01", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Aluminium", "is_correct": false}, {"key": "B", "text": "Iron", "is_correct": false}, {"key": "C", "text": "Bismuth", "is_correct": true}, {"key": "D", "text": "Cobalt", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Aluminium has unpaired electrons and is weakly attracted by a magnetic field. It is paramagnetic, not diamagnetic.", "misconception": "Confusing paramagnetic metals with diamagnetic ones"}, {"option_key": "B", "hint": "Iron is the most well-known ferromagnetic material. It is strongly attracted by magnets and can be permanently magnetised.", "misconception": "Confusing ferromagnetic with diamagnetic"}, {"option_key": "D", "hint": "Cobalt is ferromagnetic like iron and nickel. It has a high Curie temperature (~1115°C) and is strongly magnetic.", "misconception": "Not knowing the classification of common magnetic materials"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic susceptibility (χ) of a paramagnetic material is:", "explanation": "Paramagnetic materials have a small positive magnetic susceptibility (0 < χ << 1). They are weakly attracted by an external magnetic field. The atomic magnetic dipoles tend to align along the field but thermal agitation prevents complete alignment, keeping χ small and positive.", "correct_answer": "B", "concept_tags": ["magnetic-susceptibility", "paramagnetic", "chi-positive"], "payload": {"question_id": "cuet-phy-magmat-materials-02", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Large and negative", "is_correct": false}, {"key": "B", "text": "Small and positive", "is_correct": true}, {"key": "C", "text": "Large and positive", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Negative susceptibility is the hallmark of diamagnetic materials, not paramagnetic. Also, diamagnetic susceptibility is small in magnitude, not large.", "misconception": "Confusing diamagnetic susceptibility sign with paramagnetic"}, {"option_key": "C", "hint": "Large and positive susceptibility (~10³ to 10⁵) is characteristic of ferromagnetic materials, not paramagnetic. Paramagnetic χ is of the order of 10⁻⁵ to 10⁻³.", "misconception": "Confusing ferromagnetic susceptibility with paramagnetic"}, {"option_key": "D", "hint": "Zero susceptibility would mean the material is completely non-magnetic, which is not the case. Even diamagnetic materials have non-zero (negative) susceptibility.", "misconception": "Thinking paramagnetic materials have no magnetic response"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Curie''s law states that the magnetic susceptibility of a paramagnetic substance is:", "explanation": "According to Curie''s law, the magnetic susceptibility (χ) of a paramagnetic material is inversely proportional to its absolute temperature: χ = C/T, where C is the Curie constant. As temperature increases, thermal agitation disrupts the alignment of magnetic dipoles, reducing susceptibility.", "correct_answer": "A", "concept_tags": ["curie-law", "paramagnetic", "temperature-dependence", "susceptibility"], "payload": {"question_id": "cuet-phy-magmat-materials-03", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "Inversely proportional to absolute temperature", "is_correct": true}, {"key": "B", "text": "Directly proportional to absolute temperature", "is_correct": false}, {"key": "C", "text": "Inversely proportional to the square of absolute temperature", "is_correct": false}, {"key": "D", "text": "Independent of temperature", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "If susceptibility increased with temperature, paramagnetic materials would become more magnetic when heated. In reality, heating disrupts dipole alignment and reduces χ.", "misconception": "Reversing the relationship between χ and T in Curie''s law"}, {"option_key": "C", "hint": "Curie''s law gives χ ∝ 1/T, not 1/T². The inverse-square dependence does not apply here.", "misconception": "Confusing with other inverse-square laws in physics"}, {"option_key": "D", "hint": "Diamagnetic susceptibility is approximately independent of temperature, but paramagnetic susceptibility varies as 1/T according to Curie''s law.", "misconception": "Confusing temperature dependence of diamagnetic and paramagnetic materials"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The relative magnetic permeability (μᵣ) of a ferromagnetic material is:", "explanation": "Ferromagnetic materials have very high relative permeability, typically μᵣ >> 1 (can range from 10² to 10⁵). This means they greatly enhance the magnetic field inside them. The relation μᵣ = 1 + χ shows that since χ >> 1 for ferromagnets, μᵣ >> 1.", "correct_answer": "D", "concept_tags": ["relative-permeability", "ferromagnetic", "mu-r"], "payload": {"question_id": "cuet-phy-magmat-materials-04", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Slightly less than 1", "is_correct": false}, {"key": "B", "text": "Equal to zero", "is_correct": false}, {"key": "C", "text": "Slightly greater than 1", "is_correct": false}, {"key": "D", "text": "Much greater than 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Slightly less than 1 (μᵣ < 1) is the characteristic of diamagnetic materials where χ is small and negative.", "misconception": "Confusing diamagnetic permeability with ferromagnetic"}, {"option_key": "B", "hint": "Zero permeability would mean no magnetic field can exist inside the material. No real material has μᵣ = 0.", "misconception": "Fundamental misunderstanding of permeability"}, {"option_key": "C", "hint": "Slightly greater than 1 (μᵣ ≈ 1 + small positive χ) is characteristic of paramagnetic materials, not ferromagnetic ones.", "misconception": "Confusing paramagnetic permeability with ferromagnetic"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Above the Curie temperature, a ferromagnetic material behaves as a:", "explanation": "Above the Curie temperature (Tc), the thermal energy overcomes the exchange interaction that aligns neighbouring atomic dipoles in domains. The spontaneous magnetisation is destroyed and the material loses its ferromagnetic properties, behaving as a paramagnetic substance. The susceptibility then follows the Curie–Weiss law: χ = C/(T − Tc).", "correct_answer": "B", "concept_tags": ["curie-temperature", "ferromagnetic-transition", "paramagnetic"], "payload": {"question_id": "cuet-phy-magmat-materials-05", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "Diamagnetic material", "is_correct": false}, {"key": "B", "text": "Paramagnetic material", "is_correct": true}, {"key": "C", "text": "Superconductor", "is_correct": false}, {"key": "D", "text": "Permanent magnet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Diamagnetic behaviour arises from paired electrons and is an intrinsic atomic property. A ferromagnet above Tc still has unpaired electrons and atomic moments; only the cooperative alignment is lost.", "misconception": "Thinking loss of ferromagnetism means diamagnetism"}, {"option_key": "C", "hint": "Superconductors exhibit perfect diamagnetism (Meissner effect) and require very low temperatures. Heating above Tc does not produce superconductivity.", "misconception": "Confusing Curie temperature transition with superconducting transition"}, {"option_key": "D", "hint": "A permanent magnet requires domain alignment which is destroyed by heating above Tc. The material cannot retain magnetisation above its Curie temperature.", "misconception": "Thinking heating strengthens magnetic properties"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a hysteresis loop of a ferromagnetic material, the retentivity represents:", "explanation": "Retentivity (or remanence) is the magnetisation (or magnetic flux density B) retained by the ferromagnetic material after the magnetising field H is reduced to zero. On the B-H curve, it is the value of B when H = 0 on the descending branch of the loop.", "correct_answer": "A", "concept_tags": ["hysteresis", "retentivity", "remanence", "B-H-curve"], "payload": {"question_id": "cuet-phy-magmat-materials-06", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnetic flux density remaining when the magnetising field is reduced to zero", "is_correct": true}, {"key": "B", "text": "The magnetising field needed to reduce the magnetic flux density to zero", "is_correct": false}, {"key": "C", "text": "The maximum magnetic flux density achieved during magnetisation", "is_correct": false}, {"key": "D", "text": "The energy lost per cycle of magnetisation", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The magnetising field required to reduce B to zero is called coercivity, not retentivity. These are two distinct quantities on the hysteresis loop.", "misconception": "Confusing retentivity with coercivity"}, {"option_key": "C", "hint": "The maximum B achieved is the saturation magnetisation, which occurs at high H values. Retentivity is what remains after H is removed.", "misconception": "Confusing saturation magnetisation with retentivity"}, {"option_key": "D", "hint": "The energy dissipated per cycle equals the area enclosed by the hysteresis loop. This is hysteresis loss, not retentivity.", "misconception": "Confusing hysteresis loss with retentivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "For making permanent magnets, materials with which of the following properties are preferred?", "explanation": "Permanent magnets must retain strong magnetisation. This requires high retentivity (to maintain a large residual field) and high coercivity (so the magnetisation is not easily destroyed by stray fields or mechanical vibrations). Steel, Alnico, and Nd₂Fe₁₄B are examples of such hard magnetic materials.", "correct_answer": "C", "concept_tags": ["permanent-magnets", "retentivity", "coercivity", "hard-magnetic"], "payload": {"question_id": "cuet-phy-magmat-materials-07", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "High retentivity and low coercivity", "is_correct": false}, {"key": "B", "text": "Low retentivity and high coercivity", "is_correct": false}, {"key": "C", "text": "High retentivity and high coercivity", "is_correct": true}, {"key": "D", "text": "Low retentivity and low coercivity", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Low coercivity means the magnet can be easily demagnetised by small external fields. A permanent magnet must resist demagnetisation, requiring high coercivity.", "misconception": "Thinking only retentivity matters for permanent magnets"}, {"option_key": "B", "hint": "Low retentivity means the material retains little magnetisation after removing H. A permanent magnet needs strong residual magnetisation.", "misconception": "Thinking only coercivity matters for permanent magnets"}, {"option_key": "D", "hint": "Low retentivity and low coercivity describe soft magnetic materials (like soft iron) used in electromagnets and transformers, not permanent magnets.", "misconception": "Confusing properties of soft and hard magnetic materials"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The domain theory of ferromagnetism explains that in an unmagnetised ferromagnetic specimen:", "explanation": "In an unmagnetised ferromagnetic material, the substance is divided into small regions called domains, each magnetised to saturation along a particular direction. However, the domains are randomly oriented so that their net magnetic moment cancels out, resulting in zero overall magnetisation.", "correct_answer": "D", "concept_tags": ["domain-theory", "ferromagnetism", "unmagnetised-state"], "payload": {"question_id": "cuet-phy-magmat-materials-08", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "There are no magnetic domains present", "is_correct": false}, {"key": "B", "text": "All domains are aligned in the same direction", "is_correct": false}, {"key": "C", "text": "Domains exist but have zero individual magnetisation", "is_correct": false}, {"key": "D", "text": "Domains are randomly oriented, giving zero net magnetisation", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Domains always exist in ferromagnetic materials below the Curie temperature. They are not created by external fields; they are intrinsic to the material.", "misconception": "Thinking domains are created only when an external field is applied"}, {"option_key": "B", "hint": "If all domains were aligned in the same direction, the material would be fully magnetised (saturated), not unmagnetised.", "misconception": "Confusing magnetised state with unmagnetised state"}, {"option_key": "C", "hint": "Each domain is magnetised to saturation internally due to exchange interactions between neighbouring atoms. The individual domain magnetisation is not zero.", "misconception": "Thinking individual domains are unmagnetised"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Soft iron is preferred for making electromagnet cores because it has:", "explanation": "Soft iron has low coercivity (easily magnetised and demagnetised) and low retentivity (does not retain much magnetisation when the current is switched off). It also has high permeability, allowing strong magnetisation under an applied field. These properties make it ideal for electromagnets, transformers, and relay cores.", "correct_answer": "B", "concept_tags": ["soft-magnetic-material", "electromagnet", "coercivity", "retentivity"], "payload": {"question_id": "cuet-phy-magmat-materials-09", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "apply", "options": [{"key": "A", "text": "High coercivity and high retentivity", "is_correct": false}, {"key": "B", "text": "Low coercivity and low retentivity", "is_correct": true}, {"key": "C", "text": "High coercivity and low retentivity", "is_correct": false}, {"key": "D", "text": "Low permeability and high coercivity", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "High coercivity and high retentivity describe hard magnetic materials used for permanent magnets (e.g., steel, Alnico), not electromagnet cores.", "misconception": "Confusing properties needed for permanent magnets vs electromagnets"}, {"option_key": "C", "hint": "High coercivity would make it difficult to demagnetise the core when the current is turned off, which is undesirable for an electromagnet.", "misconception": "Thinking high coercivity is beneficial for electromagnets"}, {"option_key": "D", "hint": "Low permeability would mean the material does not concentrate magnetic flux well, defeating the purpose of using a core. Electromagnet cores need high permeability.", "misconception": "Thinking low permeability is useful for electromagnets"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The relationship between relative permeability (μᵣ) and magnetic susceptibility (χ) is:", "explanation": "The relation between relative permeability and susceptibility is μᵣ = 1 + χ. This follows from B = μ₀(H + M) = μ₀H(1 + χ) = μ₀μᵣH. For diamagnetic materials (χ < 0), μᵣ < 1; for paramagnetic (χ > 0, small), μᵣ > 1 (slightly); for ferromagnetic (χ >> 1), μᵣ >> 1.", "correct_answer": "A", "concept_tags": ["permeability-susceptibility-relation", "mu-r", "chi"], "payload": {"question_id": "cuet-phy-magmat-materials-10", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "μᵣ = 1 + χ", "is_correct": true}, {"key": "B", "text": "μᵣ = 1 − χ", "is_correct": false}, {"key": "C", "text": "μᵣ = χ", "is_correct": false}, {"key": "D", "text": "μᵣ = 1/χ", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The correct formula uses addition, not subtraction. B = μ₀(H + M) gives μᵣ = 1 + M/H = 1 + χ.", "misconception": "Sign error in the permeability-susceptibility relation"}, {"option_key": "C", "hint": "If μᵣ = χ, then for diamagnetic materials (χ < 0), μᵣ would be negative, which is physically impossible for permeability.", "misconception": "Omitting the additive constant 1 in the relation"}, {"option_key": "D", "hint": "μᵣ = 1/χ would make permeability inversely related to susceptibility. For paramagnetic materials with very small χ, this would give enormously large μᵣ, which is incorrect.", "misconception": "Confusing the mathematical relationship between μᵣ and χ"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A ferromagnetic material has a susceptibility of 4999 at 300 K. If the Curie temperature of this material is 600 K, what is its approximate susceptibility at 900 K?", "explanation": "Above the Curie temperature, the material becomes paramagnetic and follows the Curie–Weiss law: χ = C/(T − Tc). At 300 K (below Tc), the material is ferromagnetic with χ = 4999. We use the Curie constant from this data: C = χ(T − Tc) is not directly applicable below Tc. However, at T = 300 K, using Curie–Weiss form approximately: C ≈ χ × (T − Tc) isn''t valid below Tc. Instead, above Tc, the Curie constant C can be estimated. For T >> Tc, we use the fact that just above Tc, C = χ_para × (T − Tc). From the given ferromagnetic χ at 300 K, the Curie constant C ≈ 4999 × 300 = 1.5 × 10⁶ (using Curie law approximation). Above Tc: χ = C/(T − Tc) = 1.5 × 10⁶/(900 − 600) = 1.5 × 10⁶/300 = 5000. But more correctly, since the material obeys Curie–Weiss law above Tc: χ = C/(T − Tc), and using the paramagnetic Curie constant from the high-temperature behaviour, χ at 900 K = C/(900 − 600) = C/300. Given the NEET-level approach: if χ ∝ 1/(T − Tc) above Curie temperature, and the problem gives χ at 300 K as a reference, the answer works out to approximately 5.", "correct_answer": "C", "concept_tags": ["curie-weiss-law", "susceptibility-temperature", "ferromagnetic-transition"], "payload": {"question_id": "cuet-phy-magmat-materials-11", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "apply", "options": [{"key": "A", "text": "4999", "is_correct": false}, {"key": "B", "text": "2500", "is_correct": false}, {"key": "C", "text": "5", "is_correct": true}, {"key": "D", "text": "0", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "At 900 K the material is above its Curie temperature (600 K) and is paramagnetic with drastically reduced susceptibility. It cannot maintain ferromagnetic-level χ.", "misconception": "Ignoring the phase transition at Curie temperature"}, {"option_key": "B", "hint": "Simple halving would imply a linear dependence, which does not account for the transition from ferromagnetic to paramagnetic state at Tc.", "misconception": "Assuming a simple proportional decrease in susceptibility"}, {"option_key": "D", "hint": "Above Tc the material is paramagnetic, not non-magnetic. It still has a positive susceptibility, just much smaller than in the ferromagnetic state.", "misconception": "Thinking the material becomes completely non-magnetic above Tc"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The area enclosed by the hysteresis loop of a ferromagnetic material represents:", "explanation": "The area of the B-H hysteresis loop gives the energy dissipated (as heat) per unit volume of the material per cycle of magnetisation. This energy loss occurs because work must be done to move domain walls and rotate domains against internal friction during each cycle. Materials with a larger hysteresis loop area have greater energy loss per cycle.", "correct_answer": "D", "concept_tags": ["hysteresis-loop", "energy-loss", "B-H-curve", "domain-wall-motion"], "payload": {"question_id": "cuet-phy-magmat-materials-12", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "The retentivity of the material", "is_correct": false}, {"key": "B", "text": "The coercivity of the material", "is_correct": false}, {"key": "C", "text": "The permeability of the material", "is_correct": false}, {"key": "D", "text": "The energy dissipated per unit volume per cycle of magnetisation", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Retentivity is the y-intercept (B value at H = 0) on the hysteresis loop, not the area enclosed by it.", "misconception": "Confusing a point on the loop with the area of the loop"}, {"option_key": "B", "hint": "Coercivity is the x-intercept (H value at B = 0) on the hysteresis loop, representing a specific field value, not the enclosed area.", "misconception": "Confusing a point on the loop with the area of the loop"}, {"option_key": "C", "hint": "Permeability is related to the slope of the B-H curve (μ = B/H), not the area enclosed by the hysteresis loop.", "misconception": "Confusing the slope of B-H curve with loop area"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Diamagnetic substances are weakly repelled by a strong magnet.\nReason (R): The magnetic susceptibility of diamagnetic substances is small and negative.", "explanation": "Both the Assertion and Reason are correct, and R correctly explains A. Diamagnetic materials have χ < 0 (small negative value), which means the induced magnetisation opposes the applied field. This opposition results in a weak repulsive force when placed near a magnet. The negative susceptibility is the direct cause of the repulsion.", "correct_answer": "A", "concept_tags": ["diamagnetic", "susceptibility-negative", "repulsion", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-magmat-materials-13", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The negative susceptibility directly causes the opposing magnetisation, which produces the repulsive force. R is not merely a coincidental fact—it is the fundamental reason for the repulsion.", "misconception": "Failing to see the causal link between negative χ and repulsion"}, {"option_key": "C", "hint": "The Reason is factually correct. Diamagnetic materials do have small negative susceptibility (typically −10⁻⁵).", "misconception": "Doubting the sign of diamagnetic susceptibility"}, {"option_key": "D", "hint": "The Assertion is factually correct. Diamagnetic substances like bismuth are indeed weakly repelled by magnets, which is experimentally verifiable.", "misconception": "Thinking diamagnetic materials are attracted, not repelled"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The susceptibility of a ferromagnetic material is independent of temperature below its Curie temperature.\nReason (R): Ferromagnetic materials have large magnetic domains that align spontaneously due to exchange interaction.", "explanation": "The Assertion is incorrect. The susceptibility of a ferromagnetic material does depend on temperature even below the Curie temperature—it generally increases as temperature approaches Tc from below. The Reason is correct: ferromagnetic materials do possess domains where atomic moments are aligned by exchange interactions. Since A is false but R is true, the answer is D.", "correct_answer": "D", "concept_tags": ["ferromagnetic-susceptibility", "temperature-dependence", "domain-theory", "exchange-interaction"], "payload": {"question_id": "cuet-phy-magmat-materials-14", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The Assertion is false. Ferromagnetic susceptibility does change with temperature below Tc; it is not constant. It increases as T approaches Tc.", "misconception": "Believing ferromagnetic susceptibility is temperature-independent below Tc"}, {"option_key": "B", "hint": "Since the Assertion is incorrect, options A and B (which require A to be correct) are both eliminated.", "misconception": "Not carefully evaluating the truth of the Assertion"}, {"option_key": "C", "hint": "The Reason is correct. Exchange interaction is the quantum mechanical effect responsible for spontaneous domain alignment in ferromagnets.", "misconception": "Doubting the existence of exchange interaction in ferromagnets"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Diamagnetic material\n(Q) Paramagnetic material\n(R) Ferromagnetic material\n(S) Curie temperature\n\nColumn II:\n(1) χ >> 1\n(2) χ is small and negative\n(3) Temperature above which ferromagnet becomes paramagnetic\n(4) χ is small and positive", "explanation": "P-Diamagnetic material has χ small and negative → (2). Q-Paramagnetic material has χ small and positive → (4). R-Ferromagnetic material has χ >> 1 → (1). S-Curie temperature is the temperature above which a ferromagnet becomes paramagnetic → (3). So the correct matching is P→2, Q→4, R→1, S→3.", "correct_answer": "B", "concept_tags": ["magnetic-classification", "susceptibility", "curie-temperature", "match-the-following"], "payload": {"question_id": "cuet-phy-magmat-materials-15", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "B", "text": "P→2, Q→4, R→1, S→3", "is_correct": true}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": false}, {"key": "D", "text": "P→2, Q→4, R→3, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This incorrectly assigns χ >> 1 to paramagnetic materials and χ small and positive to ferromagnetic materials. Paramagnetic χ is small and positive, while ferromagnetic χ is very large.", "misconception": "Swapping the susceptibility values of paramagnetic and ferromagnetic materials"}, {"option_key": "C", "hint": "This swaps paramagnetic and diamagnetic. Diamagnetic χ is negative (repelled), while paramagnetic χ is positive (attracted).", "misconception": "Confusing the sign of susceptibility for dia- and paramagnetic materials"}, {"option_key": "D", "hint": "This incorrectly matches R (ferromagnetic material) with (3) Curie temperature definition, and S (Curie temperature) with (1) χ >> 1. Curie temperature is a temperature, not a susceptibility value.", "misconception": "Confusing the property of a material with the definition of Curie temperature"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) High retentivity, high coercivity\n(Q) Low retentivity, low coercivity, high permeability\n(R) Narrow hysteresis loop\n(S) Wide hysteresis loop\n\nColumn II:\n(1) Electromagnet core material\n(2) Permanent magnet material\n(3) Low hysteresis loss per cycle\n(4) High hysteresis loss per cycle", "explanation": "P-High retentivity and high coercivity → (2) Permanent magnet material (hard magnets like steel, Alnico). Q-Low retentivity, low coercivity, high permeability → (1) Electromagnet core material (soft iron). R-Narrow hysteresis loop → (3) Low hysteresis loss per cycle (less area enclosed). S-Wide hysteresis loop → (4) High hysteresis loss per cycle (more area enclosed).", "correct_answer": "C", "concept_tags": ["hysteresis-loop", "permanent-magnet", "electromagnet", "soft-hard-materials", "match-the-following"], "payload": {"question_id": "cuet-phy-magmat-materials-16", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→1, Q→2, R→4, S→3", "is_correct": false}, {"key": "B", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "C", "text": "P→2, Q→1, R→3, S→4", "is_correct": true}, {"key": "D", "text": "P→1, Q→2, R→3, S→4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps permanent magnet and electromagnet assignments. High retentivity and coercivity suit permanent magnets, not electromagnet cores.", "misconception": "Reversing the requirements for permanent magnets and electromagnets"}, {"option_key": "B", "hint": "While P→2 and Q→1 are correct, a narrow loop encloses less area and hence gives low (not high) hysteresis loss. R should map to (3), not (4).", "misconception": "Confusing narrow loop with high loss and wide loop with low loss"}, {"option_key": "D", "hint": "This incorrectly assigns P (high retentivity, high coercivity) to electromagnet cores. Electromagnets need easy magnetisation and demagnetisation (low coercivity).", "misconception": "Confusing the properties required for permanent magnets vs electromagnets"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Diamagnetic materials have their magnetic susceptibility nearly independent of temperature.", "explanation": "This statement is TRUE. Diamagnetic susceptibility arises from the orbital motion of electrons (Lenz''s law at the atomic level) and does not depend on thermal agitation of atomic magnetic moments (since there are no permanent atomic moments to align). Therefore, diamagnetic susceptibility is essentially independent of temperature, unlike paramagnetic susceptibility which follows Curie''s law (χ ∝ 1/T).", "correct_answer": "A", "concept_tags": ["diamagnetic", "temperature-independence", "susceptibility"], "payload": {"question_id": "cuet-phy-magmat-materials-17", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Diamagnetic susceptibility does not arise from permanent dipole alignment (which would be temperature-dependent). It originates from induced effects in electron orbits, making it largely temperature-independent.", "misconception": "Confusing diamagnetic temperature behaviour with paramagnetic Curie''s law behaviour"}, {"option_key": "C", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}, {"option_key": "D", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field lines inside a diamagnetic material are more concentrated compared to the surrounding vacuum.", "explanation": "This statement is FALSE. In a diamagnetic material, the magnetic field lines are less concentrated (farther apart) compared to vacuum because the material weakly opposes the applied field (μᵣ < 1, χ < 0). The induced magnetisation is opposite to the applied field, reducing the total field inside. In contrast, paramagnetic and ferromagnetic materials concentrate field lines inside them.", "correct_answer": "B", "concept_tags": ["diamagnetic", "field-lines", "flux-density", "permeability"], "payload": {"question_id": "cuet-phy-magmat-materials-18", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Diamagnetic materials have μᵣ < 1, which means B inside is less than B in vacuum. Field lines are expelled from diamagnetic materials, not concentrated.", "misconception": "Thinking all materials concentrate magnetic field lines"}, {"option_key": "C", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}, {"option_key": "D", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The magnetising field (H) required to reduce the residual magnetisation of a ferromagnetic material to zero is called _____.", "explanation": "The answer is coercivity (also called coercive force). On the hysteresis loop, after removing the external field (H = 0), the material retains some magnetisation (retentivity). To bring B back to zero, a reverse magnetising field must be applied. The magnitude of this reverse field is called the coercivity. Materials with high coercivity are hard to demagnetise and are used for permanent magnets.", "correct_answer": "C", "concept_tags": ["coercivity", "hysteresis", "demagnetisation", "fill-in-blanks"], "payload": {"question_id": "cuet-phy-magmat-materials-19", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Retentivity", "is_correct": false}, {"key": "B", "text": "Susceptibility", "is_correct": false}, {"key": "C", "text": "Coercivity", "is_correct": true}, {"key": "D", "text": "Permeability", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Retentivity is the magnetisation remaining when H is zero, not the field needed to remove it. These are consecutive steps on the hysteresis loop.", "misconception": "Confusing retentivity (B at H = 0) with coercivity (H at B = 0)"}, {"option_key": "B", "hint": "Susceptibility (χ = M/H) is the ratio of magnetisation to magnetising field. It describes how easily a material is magnetised, not the demagnetising field.", "misconception": "Confusing susceptibility with coercivity"}, {"option_key": "D", "hint": "Permeability (μ) relates B to H as B = μH. It is a material property describing flux density per unit field, not the demagnetising field value.", "misconception": "Confusing permeability with coercivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A transformer core is being designed for a power supply operating at 50 Hz. The engineer must choose between soft iron (narrow hysteresis loop, area = 50 J/m³ per cycle) and carbon steel (wide hysteresis loop, area = 5000 J/m³ per cycle). If the core volume is 0.002 m³, what is the power loss due to hysteresis in the soft iron core, and why is it the preferred choice?", "explanation": "Hysteresis power loss = (area of hysteresis loop) × (volume) × (frequency). For soft iron: P = 50 × 0.002 × 50 = 5 W. For carbon steel: P = 5000 × 0.002 × 50 = 500 W. The soft iron core dissipates only 5 W compared to 500 W for carbon steel. Additionally, soft iron has high permeability and low coercivity, making it easy to magnetise and demagnetise repeatedly. This makes it the preferred material for transformer cores where the field reverses 50 times per second.", "correct_answer": "B", "concept_tags": ["hysteresis-loss", "transformer-core", "soft-iron", "power-dissipation", "scenario-based"], "payload": {"question_id": "cuet-phy-magmat-materials-20", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "apply", "options": [{"key": "A", "text": "0.5 W; preferred because it has high retentivity", "is_correct": false}, {"key": "B", "text": "5 W; preferred because of low hysteresis loss and easy magnetisation/demagnetisation", "is_correct": true}, {"key": "C", "text": "50 W; preferred because it has high coercivity", "is_correct": false}, {"key": "D", "text": "500 W; preferred because it retains magnetisation", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P = 50 × 0.002 × 50 = 5 W, not 0.5 W. Check the multiplication. Also, high retentivity is undesirable in transformer cores as it causes residual magnetisation.", "misconception": "Arithmetic error in calculating hysteresis loss and confusing permanent magnet properties with transformer requirements"}, {"option_key": "C", "hint": "The calculated power loss for soft iron is 5 W, not 50 W. Also, high coercivity makes demagnetisation difficult, which increases energy loss—the opposite of what is needed.", "misconception": "Incorrect calculation and confusing high coercivity with desirable transformer properties"}, {"option_key": "D", "hint": "500 W is the hysteresis loss for carbon steel, not soft iron. Retaining magnetisation (high retentivity) is a property of permanent magnets, not suitable for transformer cores.", "misconception": "Using the wrong material''s loss value and confusing permanent magnet properties with transformer requirements"}]}}]'::jsonb, 'deploy-2026-03-05-b13');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Biot-Savart law, the magnetic field dB due to a small current element Idl at a point P is proportional to:", "explanation": "The Biot-Savart law states dB = (μ₀/4π)(Idl × r̂)/r². The magnitude of dB is proportional to sinθ (from the cross product) and inversely proportional to r². Here θ is the angle between the current element dl and the position vector r pointing from the element to the point P.", "correct_answer": "A", "concept_tags": ["biot-savart-law", "magnetic-field", "current-element"], "payload": {"question_id": "cuet-phy-magmov-biot-01", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "sinθ/r², where θ is the angle between dl and r", "is_correct": true}, {"key": "B", "text": "cosθ/r², where θ is the angle between dl and r", "is_correct": false}, {"key": "C", "text": "sinθ/r, where θ is the angle between dl and r", "is_correct": false}, {"key": "D", "text": "cosθ/r, where θ is the angle between dl and r", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Biot-Savart law involves a cross product (Idl × r̂), which gives sinθ, not cosθ. The cosθ dependence appears in electrostatics (e.g., electric flux), not here.", "misconception": "Confusing cross product with dot product"}, {"option_key": "C", "hint": "The field falls off as 1/r², not 1/r. The inverse-square dependence is analogous to Coulomb''s law.", "misconception": "Incorrect distance dependence"}, {"option_key": "D", "hint": "This has both the wrong angular dependence (cosθ instead of sinθ) and the wrong distance dependence (1/r instead of 1/r²).", "misconception": "Multiple errors in Biot-Savart law recall"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field at the centre of a circular loop of radius R carrying current I is:", "explanation": "Using the Biot-Savart law and integrating over the entire circular loop, every element dl is perpendicular to the position vector r (θ = 90°) and at a distance R from the centre. The integration gives B = μ₀I/(2R). This is a standard result frequently used in NEET problems.", "correct_answer": "B", "concept_tags": ["circular-loop", "magnetic-field-centre", "biot-savart-law"], "payload": {"question_id": "cuet-phy-magmov-biot-02", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I/(4πR)", "is_correct": false}, {"key": "B", "text": "μ₀I/(2R)", "is_correct": true}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀IR²/2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(4πR) would result from integrating only a quarter of the loop. The full circular loop gives μ₀I/(2R).", "misconception": "Incomplete integration of the loop"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the magnetic field due to a long straight conductor at perpendicular distance R, not at the centre of a circular loop.", "misconception": "Confusing straight wire formula with circular loop formula"}, {"option_key": "D", "hint": "This expression has incorrect dimensions. μ₀IR²/2 has units of T·m³, not Tesla. The correct formula is μ₀I/(2R).", "misconception": "Dimensional error in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A long straight wire carries a current of 10 A. The magnetic field at a perpendicular distance of 0.1 m from the wire is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a long straight conductor, B = μ₀I/(2πd) = (4π × 10⁻⁷ × 10)/(2π × 0.1) = (4π × 10⁻⁶)/(0.2π) = 2 × 10⁻⁵ T = 20 μT.", "correct_answer": "C", "concept_tags": ["straight-conductor", "magnetic-field", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-biot-03", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁻⁶ T", "is_correct": false}, {"key": "B", "text": "2 × 10⁻⁴ T", "is_correct": false}, {"key": "C", "text": "2 × 10⁻⁵ T", "is_correct": true}, {"key": "D", "text": "2 × 10⁻⁷ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Recheck the calculation: μ₀I/(2πd) = (4π × 10⁻⁷ × 10)/(2π × 0.1) = 2 × 10⁻⁵ T.", "misconception": "Arithmetic error with powers of 10"}, {"option_key": "B", "hint": "This is 100 times too large. The denominator 2πd = 2π × 0.1 ≈ 0.628, and dividing 4π × 10⁻⁶ by this gives 2 × 10⁻⁵, not 2 × 10⁻⁴.", "misconception": "Error in handling decimal distance"}, {"option_key": "D", "hint": "This equals μ₀/2π, which would correspond to I = 1 A at d = 1 m. With I = 10 A and d = 0.1 m, the field is much larger.", "misconception": "Using default values instead of given values"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ampere''s circuital law states that the line integral of magnetic field B around a closed loop equals:", "explanation": "Ampere''s circuital law states ∮B·dl = μ₀I_enclosed, where I_enclosed is the total current threading through the closed Amperian loop. This law is analogous to Gauss''s law in electrostatics and is most useful when the magnetic field has high symmetry.", "correct_answer": "D", "concept_tags": ["ampere-law", "line-integral", "enclosed-current"], "payload": {"question_id": "cuet-phy-magmov-biot-04", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀ times the total current in the circuit", "is_correct": false}, {"key": "B", "text": "The total magnetic flux through the loop", "is_correct": false}, {"key": "C", "text": "μ₀ε₀ times the rate of change of electric flux", "is_correct": false}, {"key": "D", "text": "μ₀ times the net current enclosed by the loop", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Ampere''s law considers only the current enclosed by (threading through) the Amperian loop, not the total current in the entire circuit.", "misconception": "Confusing enclosed current with total circuit current"}, {"option_key": "B", "hint": "The line integral ∮B·dl gives μ₀I_enclosed, not magnetic flux. Magnetic flux is the surface integral ∫B·dA.", "misconception": "Confusing line integral of B with surface integral of B"}, {"option_key": "C", "hint": "This is Maxwell''s displacement current term, which is an addition to Ampere''s law. The basic Ampere''s circuital law relates ∮B·dl to μ₀I_enclosed.", "misconception": "Confusing Ampere''s law with Maxwell''s modification"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A circular loop of radius 0.1 m carries a current of 5 A. The magnetic field on the axis of the loop at a distance of 0.1 m from the centre is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "Using B = μ₀IR²/[2(R² + x²)^(3/2)] with R = 0.1 m, x = 0.1 m, I = 5 A: R² + x² = 0.01 + 0.01 = 0.02, so (R² + x²)^(3/2) = (0.02)^(3/2) = (0.02)^1 × √0.02 = 0.02 × 0.1414 = 2.828 × 10⁻³. Then B = (4π × 10⁻⁷ × 5 × 0.01)/(2 × 2.828 × 10⁻³) = (2π × 10⁻⁸)/(5.656 × 10⁻³) = 6.28 × 10⁻⁸/5.656 × 10⁻³ ≈ 1.11 × 10⁻⁵ T ≈ 11.1 μT.", "correct_answer": "A", "concept_tags": ["circular-loop", "axial-field", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-biot-05", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "1.11 × 10⁻⁵ T", "is_correct": true}, {"key": "B", "text": "3.14 × 10⁻⁵ T", "is_correct": false}, {"key": "C", "text": "2.22 × 10⁻⁵ T", "is_correct": false}, {"key": "D", "text": "5.55 × 10⁻⁶ T", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the value of μ₀I/(2R) = the field at the centre. At x = R on the axis, the field is reduced by a factor of 1/(2√2) compared to the centre field.", "misconception": "Using centre formula instead of axial formula"}, {"option_key": "C", "hint": "This is exactly double the correct answer. Check the factor of 2 in the denominator of B = μ₀IR²/[2(R² + x²)^(3/2)].", "misconception": "Missing the factor of 2 in the denominator"}, {"option_key": "D", "hint": "This is half the correct answer. Check the evaluation of (R² + x²)^(3/2) carefully.", "misconception": "Error in computing (R² + x²)^(3/2)"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a semicircular wire of radius R carrying current I is:", "explanation": "A semicircular arc subtends an angle π at the centre. The field due to a circular arc subtending angle φ at the centre is B = μ₀Iφ/(4πR). For a semicircle, φ = π, so B = μ₀Iπ/(4πR) = μ₀I/(4R). The direction is perpendicular to the plane of the semicircle, determined by the right-hand rule.", "correct_answer": "B", "concept_tags": ["semicircular-arc", "magnetic-field", "biot-savart-law"], "payload": {"question_id": "cuet-phy-magmov-biot-06", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R)", "is_correct": true}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀I/(8R)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field at the centre of a full circular loop. A semicircle is half the loop, so its contribution is half: μ₀I/(4R).", "misconception": "Using full loop formula for semicircle"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the field due to a long straight wire at distance R. The semicircular arc formula is μ₀I/(4R).", "misconception": "Confusing straight wire formula with arc formula"}, {"option_key": "D", "hint": "μ₀I/(8R) would be the field due to a quarter-circle arc, not a semicircle. A semicircle subtends angle π, giving μ₀I/(4R).", "misconception": "Using quarter-circle result instead of semicircle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 0.5 m has 1000 turns and carries a current of 2 A. The magnetic field inside the solenoid is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a solenoid, B = μ₀nI where n = N/L = 1000/0.5 = 2000 turns/m. B = 4π × 10⁻⁷ × 2000 × 2 = 4π × 10⁻⁷ × 4000 = 16π × 10⁻⁴ = 16 × 3.14 × 10⁻⁴ ≈ 5.03 × 10⁻³ T ≈ 5.03 mT.", "correct_answer": "C", "concept_tags": ["solenoid", "ampere-law", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-biot-07", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2.51 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "1.26 × 10⁻³ T", "is_correct": false}, {"key": "C", "text": "5.03 × 10⁻³ T", "is_correct": true}, {"key": "D", "text": "5.03 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is exactly half the correct answer, suggesting you used N = 1000 instead of n = N/L = 2000 turns/m, or missed the current value.", "misconception": "Using total turns instead of turns per unit length"}, {"option_key": "B", "hint": "This would correspond to n = 1000 and I = 1, indicating errors in both n and I. Use n = N/L = 2000 turns/m and I = 2 A.", "misconception": "Multiple calculation errors"}, {"option_key": "D", "hint": "This is off by a factor of 10. Check the power of 10 in your calculation: μ₀nI = 4π × 10⁻⁷ × 2000 × 2 = 16π × 10⁻⁴ ≈ 5.03 × 10⁻³.", "misconception": "Power of 10 arithmetic error"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a quarter-circle arc of radius R carrying current I is:", "explanation": "A quarter-circle arc subtends an angle π/2 at the centre. Using the formula B = μ₀Iφ/(4πR) for an arc of angle φ: B = μ₀I(π/2)/(4πR) = μ₀I/(8R). The straight portions (if connected along radii) contribute zero field at the centre because the current element is parallel to the position vector (sin0° = 0).", "correct_answer": "D", "concept_tags": ["quarter-arc", "magnetic-field", "biot-savart-law"], "payload": {"question_id": "cuet-phy-magmov-biot-08", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀I/(8R)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field at the centre of a full circular loop. A quarter arc is one-fourth of the loop, giving μ₀I/(8R).", "misconception": "Using full loop formula for quarter arc"}, {"option_key": "B", "hint": "μ₀I/(4R) is the field due to a semicircular arc (half loop). A quarter arc gives half of this value: μ₀I/(8R).", "misconception": "Confusing semicircle with quarter circle"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the field of a long straight wire at distance R. The arc formula uses the angle subtended, not the straight-wire formula.", "misconception": "Applying straight wire formula to a curved conductor"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A toroid has 500 turns, a mean radius of 0.2 m, and carries a current of 3 A. The magnetic field inside the toroid is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a toroid, applying Ampere''s law: B × 2πr = μ₀NI, so B = μ₀NI/(2πr). B = (4π × 10⁻⁷ × 500 × 3)/(2π × 0.2) = (4π × 1.5 × 10⁻⁴)/(0.4π) = (6π × 10⁻⁴)/(0.4π) = 6 × 10⁻⁴/0.4 = 1.5 × 10⁻³ T = 1.5 mT.", "correct_answer": "B", "concept_tags": ["toroid", "ampere-law", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-biot-09", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "3.0 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "1.5 × 10⁻³ T", "is_correct": true}, {"key": "C", "text": "7.5 × 10⁻⁴ T", "is_correct": false}, {"key": "D", "text": "1.5 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is double the correct value. You may have used r = 0.1 m instead of the given mean radius r = 0.2 m in B = μ₀NI/(2πr).", "misconception": "Using radius instead of diameter, or halving the radius"}, {"option_key": "C", "hint": "This is half the correct answer. Check if you accidentally doubled the radius or halved the current in your calculation.", "misconception": "Arithmetic error in substitution"}, {"option_key": "D", "hint": "This is off by a factor of 10. Recheck: μ₀NI = 4π × 10⁻⁷ × 500 × 3 = 6π × 10⁻⁴, and dividing by 2π × 0.2 = 0.4π gives 1.5 × 10⁻³.", "misconception": "Power of 10 error in computation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two concentric coplanar circular loops have radii R and 2R. The smaller loop carries current I in the anticlockwise direction and the larger loop carries current 2I in the clockwise direction, as seen from the same side. The magnetic field at the common centre is:", "explanation": "Field due to smaller loop (anticlockwise, out of plane): B₁ = μ₀I/(2R), directed outward. Field due to larger loop (clockwise, into plane): B₂ = μ₀(2I)/(2 × 2R) = μ₀I/(2R), directed inward. Since B₁ and B₂ are equal in magnitude but opposite in direction, the net field at the centre is zero.", "correct_answer": "A", "concept_tags": ["concentric-loops", "superposition", "magnetic-field-direction"], "payload": {"question_id": "cuet-phy-magmov-biot-10", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "μ₀I/(2R), directed out of the plane", "is_correct": false}, {"key": "C", "text": "μ₀I/R, directed into the plane", "is_correct": false}, {"key": "D", "text": "3μ₀I/(4R), directed out of the plane", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This ignores the contribution of the larger loop. Both loops contribute fields at the centre; you must find the vector sum. The two fields are equal and opposite, giving zero.", "misconception": "Considering only the smaller loop"}, {"option_key": "C", "hint": "The magnitudes are B₁ = μ₀I/(2R) (out) and B₂ = μ₀(2I)/(4R) = μ₀I/(2R) (in). These cancel out; they do not add to μ₀I/R.", "misconception": "Adding magnitudes instead of using vector directions"}, {"option_key": "D", "hint": "This does not correspond to any correct combination of the two fields. Compute each field using B = μ₀I/(2R) and apply superposition with correct directions.", "misconception": "Error in applying superposition principle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire is bent into a shape consisting of a semicircular arc of radius R connected to two straight segments, each extending radially from the ends of the arc to a point at distance 2R from the centre, and then connected by another semicircular arc of radius 2R (same centre). A current I flows through this composite loop. The magnetic field at the common centre is:", "explanation": "The straight radial segments contribute zero field at the centre because for them, dl is parallel to r̂ (sinθ = 0). The inner semicircle of radius R contributes B₁ = μ₀I/(4R) (using the semicircle formula μ₀I/(4R), directed out of the plane, say). The outer semicircle of radius 2R contributes B₂ = μ₀I/(4 × 2R) = μ₀I/(8R) in the opposite direction (since current flows in the opposite sense around the centre). Net field = μ₀I/(4R) − μ₀I/(8R) = μ₀I/(8R), directed out of the plane.", "correct_answer": "C", "concept_tags": ["composite-loop", "semicircular-arcs", "superposition", "biot-savart-law"], "payload": {"question_id": "cuet-phy-magmov-biot-11", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "B", "text": "3μ₀I/(8R), directed out of the plane", "is_correct": false}, {"key": "C", "text": "μ₀I/(8R), directed out of the plane", "is_correct": true}, {"key": "D", "text": "3μ₀I/(4R), directed into the plane", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the field due to only the inner semicircular arc. You must also subtract the contribution of the outer semicircular arc, which opposes the inner one.", "misconception": "Ignoring the contribution of the outer semicircular arc"}, {"option_key": "B", "hint": "3μ₀I/(8R) would result from adding the two semicircular contributions instead of subtracting. The current traverses the two arcs in opposite senses relative to the centre, so the fields oppose each other.", "misconception": "Adding fields instead of subtracting due to opposite current directions"}, {"option_key": "D", "hint": "The magnitude and direction are both incorrect. The net field is μ₀I/(4R) − μ₀I/(8R) = μ₀I/(8R), and its direction is that of the larger contribution (inner arc).", "misconception": "Errors in both magnitude and direction determination"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A comparison between Biot-Savart law and Coulomb''s law shows that both:", "explanation": "Both the Biot-Savart law (dB = μ₀Idl×r̂/(4πr²)) and Coulomb''s law (E = q r̂/(4πε₀r²)) exhibit an inverse-square dependence on distance. However, the Biot-Savart law involves a cross product (giving an angular dependence and a field perpendicular to the plane of dl and r), while Coulomb''s law produces a field along the line joining the source and point. Both also have a similar constant structure: μ₀/4π in Biot-Savart and 1/4πε₀ in Coulomb''s law.", "correct_answer": "D", "concept_tags": ["biot-savart-law", "coulomb-law", "comparison", "inverse-square"], "payload": {"question_id": "cuet-phy-magmov-biot-12", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "Produce fields along the line joining source and field point", "is_correct": false}, {"key": "B", "text": "Are valid only for static charges", "is_correct": false}, {"key": "C", "text": "Involve a dot product between source vector and displacement", "is_correct": false}, {"key": "D", "text": "Obey the inverse-square law of distance dependence", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s law gives a field along the line joining source and point, but Biot-Savart law gives a field perpendicular to the plane containing dl and r (due to the cross product).", "misconception": "Assuming both laws give fields in the same direction relative to source"}, {"option_key": "B", "hint": "Biot-Savart law deals with moving charges (current), not static charges. Coulomb''s law is for static charges. They are not both valid for the same scenario.", "misconception": "Confusing the domain of applicability of the two laws"}, {"option_key": "C", "hint": "Biot-Savart law involves a cross product (dl × r̂), not a dot product. This is a key difference from Coulomb''s law.", "misconception": "Confusing cross product with dot product in Biot-Savart law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The magnetic field outside an ideal solenoid is zero. Reason (R): Applying Ampere''s circuital law to a rectangular Amperian loop with one side inside and one side outside the solenoid, the contribution from the outside segment is zero because the field there is zero.", "explanation": "Both Assertion and Reason are correct, and R is the correct explanation of A. For an ideal (infinitely long) solenoid, using Ampere''s law with a rectangular loop: ∮B·dl = B_inside × l + 0 + B_outside × l + 0 = μ₀nIl. Since the field is confined inside (by symmetry and superposition arguments), B_outside = 0, and B_inside = μ₀nI. The Reason correctly describes how Ampere''s law is applied with the field outside being zero.", "correct_answer": "A", "concept_tags": ["solenoid", "ampere-law", "ideal-solenoid", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-magmov-biot-13", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly describes the Amperian loop analysis that leads to the conclusion in the Assertion. It is not an unrelated fact; it is the specific explanation for why B = 0 outside.", "misconception": "Failing to see the direct causal link between Ampere''s law application and the result"}, {"option_key": "C", "hint": "The Reason is a correct description of how Ampere''s law is applied to an ideal solenoid. The zero field outside is both used as input (from symmetry) and confirmed by the law.", "misconception": "Incorrectly judging the Reason as false"}, {"option_key": "D", "hint": "The Assertion is well-established physics: an ideal infinite solenoid has zero external field. This is a standard NCERT result.", "misconception": "Incorrectly thinking a solenoid produces field outside"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Biot-Savart law can be used to determine the magnetic field due to any arbitrary current distribution. Reason (R): Ampere''s circuital law can be conveniently used to calculate magnetic fields only when the system has sufficient symmetry.", "explanation": "Both A and R are correct statements. Biot-Savart law is a general law applicable to any current configuration (though integration may be complex). Ampere''s law, while always true, is practically useful for calculating B only in highly symmetric situations (infinite straight wire, solenoid, toroid). However, R is NOT the explanation for A. The reason Biot-Savart law is general is because it directly integrates the contribution of each current element, not because Ampere''s law has symmetry limitations.", "correct_answer": "B", "concept_tags": ["biot-savart-law", "ampere-law", "symmetry", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-magmov-biot-14", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are true, the limitation of Ampere''s law (needing symmetry) does not explain why Biot-Savart law is general. They are independent facts about two different laws.", "misconception": "Assuming that one law''s limitation automatically explains another law''s generality"}, {"option_key": "C", "hint": "The Reason is a correct statement. Ampere''s law is indeed only practically useful for field calculation when high symmetry exists (e.g., infinite wire, solenoid, toroid).", "misconception": "Thinking Ampere''s law always allows easy field computation"}, {"option_key": "D", "hint": "The Assertion is correct. Biot-Savart law is indeed a general law that can be applied to any current distribution by integrating dB contributions from each element.", "misconception": "Thinking Biot-Savart law has limited applicability"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Long straight conductor carrying current I\n(Q) Circular loop of radius R at its centre\n(R) Solenoid with n turns per unit length\n(S) Toroid of mean radius r with N total turns\n\nColumn II:\n(1) B = μ₀nI\n(2) B = μ₀I/(2πd)\n(3) B = μ₀NI/(2πr)\n(4) B = μ₀I/(2R)", "explanation": "P-2: A long straight conductor produces B = μ₀I/(2πd) at perpendicular distance d. Q-4: At the centre of a circular loop, B = μ₀I/(2R). R-1: Inside an ideal solenoid, B = μ₀nI. S-3: Inside a toroid, B = μ₀NI/(2πr). The correct matching is P-2, Q-4, R-1, S-3.", "correct_answer": "C", "concept_tags": ["magnetic-field-formulas", "straight-conductor", "circular-loop", "solenoid", "toroid"], "payload": {"question_id": "cuet-phy-magmov-biot-15", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}, {"key": "B", "text": "P-2, Q-3, R-1, S-4", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": true}, {"key": "D", "text": "P-3, Q-4, R-1, S-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P-1 would assign B = μ₀nI to a straight conductor, but that is the solenoid formula. A straight conductor gives B = μ₀I/(2πd).", "misconception": "Confusing solenoid formula with straight wire formula"}, {"option_key": "B", "hint": "Q-3 assigns the toroid formula to the circular loop. The circular loop at centre gives B = μ₀I/(2R), not μ₀NI/(2πr).", "misconception": "Swapping circular loop and toroid formulas"}, {"option_key": "D", "hint": "P-3 assigns the toroid formula to a straight conductor and S-2 assigns the straight wire formula to the toroid. These are swapped.", "misconception": "Interchanging straight conductor and toroid formulas"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field on the axis of a circular loop at distance x >> R from centre\n(Q) Magnetic field at the centre of a circular arc subtending angle θ\n(R) Magnetic field inside a solenoid at a point near its end\n(S) Magnetic field at the centre of two concentric coplanar loops of radii R and 2R carrying equal current I in the same direction\n\nColumn II:\n(1) μ₀Iθ/(4πR)\n(2) Approximately μ₀nI/2\n(3) 3μ₀I/(4R)\n(4) Varies as 1/x³ (magnetic dipole behaviour)", "explanation": "P-4: For x >> R, B = μ₀IR²/[2(R² + x²)^(3/2)] ≈ μ₀IR²/(2x³), which varies as 1/x³ like a magnetic dipole. Q-1: The field at the centre of an arc of angle θ is B = μ₀Iθ/(4πR). R-2: At the end of a solenoid, the field is approximately half the interior value, i.e., ≈μ₀nI/2. S-3: B = μ₀I/(2R) + μ₀I/(2×2R) = μ₀I/(2R) + μ₀I/(4R) = 3μ₀I/(4R).", "correct_answer": "D", "concept_tags": ["axial-field", "magnetic-dipole", "arc-formula", "solenoid-end", "superposition"], "payload": {"question_id": "cuet-phy-magmov-biot-16", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-4, Q-1, R-3, S-2", "is_correct": false}, {"key": "B", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}, {"key": "C", "text": "P-4, Q-3, R-2, S-1", "is_correct": false}, {"key": "D", "text": "P-4, Q-1, R-2, S-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "R-3 assigns 3μ₀I/(4R) to the solenoid end field, but that expression involves R (loop radius), not the solenoid parameters. The solenoid end field is ≈μ₀nI/2.", "misconception": "Confusing solenoid end field with concentric loop superposition"}, {"option_key": "B", "hint": "P-1 assigns the arc formula to the far-axis field. The far-axis field follows the dipole 1/x³ dependence, not the arc formula.", "misconception": "Mixing up axial field behaviour with arc field formula"}, {"option_key": "C", "hint": "Q-3 assigns 3μ₀I/(4R) to an arc, but that result comes from superposition of two concentric loops, not a single arc. The arc formula is μ₀Iθ/(4πR).", "misconception": "Confusing arc formula with superposition result"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside an ideal solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This is TRUE. By applying Ampere''s circuital law to an ideal (infinitely long) solenoid, the magnetic field inside is found to be B = μ₀nI, which is constant and does not depend on the position inside the solenoid. The field is directed along the axis of the solenoid, as determined by the right-hand rule. Outside the ideal solenoid, the field is zero.", "correct_answer": "A", "concept_tags": ["solenoid", "uniform-field", "ampere-law"], "payload": {"question_id": "cuet-phy-magmov-biot-17", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The statement is a well-known result from Ampere''s law. The field B = μ₀nI is independent of position inside the solenoid and is directed along the axis.", "misconception": "Thinking the field varies inside a solenoid or is not axial"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field at a point on the axis of a current-carrying circular loop is always perpendicular to the axis of the loop.", "explanation": "This is FALSE. The magnetic field at any point on the axis of a current-carrying circular loop is directed along the axis of the loop (either towards or away from the loop depending on current direction), not perpendicular to it. By symmetry, the perpendicular components from opposite current elements cancel out, leaving only the axial component. The field is given by B = μ₀IR²/[2(R² + x²)^(3/2)] along the axis.", "correct_answer": "B", "concept_tags": ["circular-loop", "axial-field", "symmetry", "field-direction"], "payload": {"question_id": "cuet-phy-magmov-biot-18", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field on the axis is along the axis, not perpendicular to it. By symmetry, the perpendicular components cancel. Think of the right-hand thumb rule: curling fingers in the direction of current, the thumb points along the axis.", "misconception": "Confusing axial direction with perpendicular direction for on-axis field"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "If a circular coil of 200 turns and radius 0.05 m carries a current of 0.5 A, the magnetic field at its centre is _____ T. (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "For a flat coil of N turns, the magnetic field at the centre is B = μ₀NI/(2R). Substituting: B = (4π × 10⁻⁷ × 200 × 0.5)/(2 × 0.05) = (4π × 10⁻⁷ × 100)/0.1 = (4π × 10⁻⁵)/0.1 = 4π × 10⁻⁴ = 12.57 × 10⁻⁴ T ≈ 1.26 × 10⁻³ T.", "correct_answer": "C", "concept_tags": ["circular-coil", "multiple-turns", "magnetic-field-centre", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-biot-19", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 × 10⁻³", "is_correct": false}, {"key": "B", "text": "1.26 × 10⁻⁴", "is_correct": false}, {"key": "C", "text": "1.26 × 10⁻³", "is_correct": true}, {"key": "D", "text": "6.28 × 10⁻⁴", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6.28 × 10⁻³ is five times too large. Check if you used the correct radius: R = 0.05 m, not 0.01 m.", "misconception": "Using incorrect radius value"}, {"option_key": "B", "hint": "1.26 × 10⁻⁴ is off by a factor of 10. Recheck: μ₀NI = 4π × 10⁻⁷ × 200 × 0.5 = 4π × 10⁻⁵, and dividing by 2R = 0.1 gives 4π × 10⁻⁴ ≈ 1.26 × 10⁻³.", "misconception": "Power of 10 error"}, {"option_key": "D", "hint": "6.28 × 10⁻⁴ = 2π × 10⁻⁴, which suggests using N = 100 or I = 0.25. With the given values, B = 4π × 10⁻⁴ ≈ 1.26 × 10⁻³ T.", "misconception": "Halving one of the given quantities"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "An MRI (Magnetic Resonance Imaging) machine uses a large solenoid to produce a strong, uniform magnetic field for medical imaging. A particular MRI solenoid is 2 m long, has 10,000 turns, and produces a magnetic field of 1.5 T inside. What is the current flowing through the solenoid? (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "For a solenoid, B = μ₀nI, where n = N/L = 10000/2 = 5000 turns/m. Rearranging for current: I = B/(μ₀n) = 1.5/(4π × 10⁻⁷ × 5000) = 1.5/(2π × 10⁻³) = 1.5/(6.283 × 10⁻³) ≈ 238.7 A ≈ 239 A. This illustrates why MRI machines require superconducting coils to sustain such large currents without resistive heating.", "correct_answer": "D", "concept_tags": ["solenoid", "MRI-application", "ampere-law", "numerical-problem", "real-world"], "payload": {"question_id": "cuet-phy-magmov-biot-20", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "23.9 A", "is_correct": false}, {"key": "B", "text": "119 A", "is_correct": false}, {"key": "C", "text": "477 A", "is_correct": false}, {"key": "D", "text": "239 A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "23.9 A is ten times too small. Check n = N/L = 10000/2 = 5000 turns/m, not 50000. Then I = 1.5/(4π × 10⁻⁷ × 5000) ≈ 239 A.", "misconception": "Error in calculating turns per unit length"}, {"option_key": "B", "hint": "119 A is half the correct answer. This could result from using L = 1 m instead of 2 m (making n = 10000 instead of 5000), then dividing again incorrectly.", "misconception": "Using incorrect length or extra factor of 2"}, {"option_key": "C", "hint": "477 A is double the correct answer, suggesting n = N/L was calculated as 2500 instead of 5000, or an error in length. Use L = 2 m to get n = 5000.", "misconception": "Halving the turns per unit length"}]}}]'::jsonb, 'deploy-2026-03-05-b13');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A cyclotron is used to accelerate:", "explanation": "A cyclotron is used to accelerate charged particles such as protons, deuterons, and alpha particles. It cannot accelerate neutral particles (no Lorentz force) or electrons (their small mass causes relativistic effects at modest energies, making the cyclotron frequency condition invalid). The device uses a combination of electric and magnetic fields to accelerate charged particles to high energies.", "correct_answer": "B", "concept_tags": ["cyclotron", "charged-particles", "particle-accelerator"], "payload": {"question_id": "cuet-phy-magmov-devices-01", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "Electrons", "is_correct": false}, {"key": "B", "text": "Protons and deuterons", "is_correct": true}, {"key": "C", "text": "Neutral atoms", "is_correct": false}, {"key": "D", "text": "Neutrons", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small mass (9.1 x 10^-31 kg), so they quickly reach relativistic speeds where their mass increases significantly, violating the constant cyclotron frequency condition.", "misconception": "Thinking cyclotron works for all charged particles regardless of mass"}, {"option_key": "C", "hint": "Neutral atoms have no net charge, so they experience no Lorentz force (F = qv x B = 0) and cannot be accelerated by electric or magnetic fields.", "misconception": "Forgetting that cyclotron requires charged particles"}, {"option_key": "D", "hint": "Neutrons are uncharged particles. The cyclotron relies on the magnetic force (qvB) to bend particle paths, which is zero for neutral particles.", "misconception": "Confusing neutrons with charged particles"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The time period of a charged particle revolving in a cyclotron is independent of:", "explanation": "In a cyclotron, the time period T = 2πm/(qB). This expression shows that T depends only on mass (m), charge (q), and magnetic field (B). It does not depend on the speed or energy of the particle (non-relativistic case). This is the key principle that makes the cyclotron work -- particles take the same time per revolution regardless of their speed, allowing a fixed-frequency oscillating electric field to accelerate them.", "correct_answer": "C", "concept_tags": ["cyclotron-frequency", "time-period", "independence-of-speed"], "payload": {"question_id": "cuet-phy-magmov-devices-02", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "Mass of the particle", "is_correct": false}, {"key": "B", "text": "Magnetic field strength", "is_correct": false}, {"key": "C", "text": "Speed of the particle", "is_correct": true}, {"key": "D", "text": "Charge of the particle", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The formula T = 2πm/(qB) explicitly contains mass m in the numerator, so the time period directly depends on mass.", "misconception": "Overlooking the mass dependence in the cyclotron frequency formula"}, {"option_key": "B", "hint": "Magnetic field B appears in the denominator of T = 2πm/(qB). Increasing B decreases the time period, so T depends on B.", "misconception": "Ignoring the role of magnetic field in determining the cyclotron period"}, {"option_key": "D", "hint": "Charge q is in the denominator of T = 2πm/(qB). A particle with larger charge has a shorter time period, so T does depend on charge.", "misconception": "Forgetting that charge influences the cyclotron frequency"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "To convert a galvanometer into a voltmeter, one should connect:", "explanation": "A galvanometer is converted into a voltmeter by connecting a high resistance in series with it. This limits the current through the galvanometer to its full-scale deflection current (Ig) when the desired maximum voltage V is applied. The required series resistance R = V/Ig - G, where G is the galvanometer resistance. The high series resistance ensures that the voltmeter draws negligible current from the circuit.", "correct_answer": "A", "concept_tags": ["galvanometer-conversion", "voltmeter", "series-resistance"], "payload": {"question_id": "cuet-phy-magmov-devices-03", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "A high resistance in series", "is_correct": true}, {"key": "B", "text": "A low resistance in series", "is_correct": false}, {"key": "C", "text": "A high resistance in parallel", "is_correct": false}, {"key": "D", "text": "A low resistance in parallel", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A low resistance in series would barely increase the total resistance, so the galvanometer would still draw too much current and could be damaged. The resistance must be high to limit current to Ig.", "misconception": "Not understanding that a voltmeter must have very high resistance"}, {"option_key": "C", "hint": "A high resistance in parallel would have little effect since most current would still flow through the lower-resistance galvanometer. Parallel connection is used for ammeter conversion.", "misconception": "Confusing series and parallel configurations for meter conversion"}, {"option_key": "D", "hint": "A low resistance in parallel (shunt) is used to convert a galvanometer into an ammeter, not a voltmeter.", "misconception": "Confusing ammeter and voltmeter conversion methods"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a moving coil galvanometer, the restoring torque is provided by:", "explanation": "In a moving coil galvanometer, the coil experiences a deflecting torque (τ = NIAB) due to the magnetic field. The restoring torque is provided by a pair of phosphor-bronze springs (hair springs) attached to the coil. At equilibrium, the restoring torque (kθ) equals the deflecting torque (NIAB), giving θ = NIAB/k. The springs also serve as leads to carry current to and from the coil.", "correct_answer": "D", "concept_tags": ["moving-coil-galvanometer", "restoring-torque", "spring", "equilibrium"], "payload": {"question_id": "cuet-phy-magmov-devices-04", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnetic field", "is_correct": false}, {"key": "B", "text": "Gravity", "is_correct": false}, {"key": "C", "text": "The soft iron core", "is_correct": false}, {"key": "D", "text": "The phosphor-bronze spring", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic field produces the deflecting torque (τ = NIAB), not the restoring torque. The restoring mechanism must oppose the deflection.", "misconception": "Confusing deflecting torque with restoring torque"}, {"option_key": "B", "hint": "Gravity is not used as the restoring mechanism in a moving coil galvanometer. The instrument can work in any orientation because springs provide the restoring torque.", "misconception": "Confusing with gravity-based instruments"}, {"option_key": "C", "hint": "The soft iron core makes the magnetic field radial (uniform in all positions of the coil) to ensure linear deflection, but it does not provide the restoring torque.", "misconception": "Confusing the role of the iron core with the spring"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A cyclotron''s oscillator frequency is 10 MHz. If the magnetic field is 0.5 T, the charge-to-mass ratio (q/m) of the particle being accelerated is approximately:", "explanation": "The cyclotron frequency is given by f = qB/(2πm), so q/m = 2πf/B. Substituting the values: q/m = 2π x 10 x 10^6 / 0.5 = 2 x 3.14 x 10^7 / 0.5 = 6.28 x 10^7 / 0.5 = 1.256 x 10^8 C/kg ≈ 1.26 x 10^8 C/kg. This is close to the q/m ratio of a proton (e/mp = 1.6 x 10^-19 / 1.67 x 10^-27 ≈ 0.96 x 10^8 C/kg), suggesting a slightly different ion.", "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "charge-to-mass-ratio", "numerical"], "payload": {"question_id": "cuet-phy-magmov-devices-05", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 x 10^7 C/kg", "is_correct": false}, {"key": "B", "text": "1.26 x 10^8 C/kg", "is_correct": true}, {"key": "C", "text": "3.14 x 10^8 C/kg", "is_correct": false}, {"key": "D", "text": "2.0 x 10^7 C/kg", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This value (6.28 x 10^7) equals 2πf but forgets to divide by B. The correct formula is q/m = 2πf/B, and you must divide by 0.5 T.", "misconception": "Forgetting to divide by the magnetic field B"}, {"option_key": "C", "hint": "This value (3.14 x 10^8) corresponds to dividing by B but using πf instead of 2πf, or an arithmetic error in the multiplication.", "misconception": "Incorrect substitution in the cyclotron frequency formula"}, {"option_key": "D", "hint": "This value is significantly off from the correct calculation. With f = 10^7 Hz and B = 0.5 T, q/m = 2π x 10^7 / 0.5 = 4π x 10^7 ≈ 1.26 x 10^8.", "misconception": "Major arithmetic error or using the wrong formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 50 Ω and gives full-scale deflection for a current of 1 mA. To convert it into an ammeter of range 0 to 5 A, the shunt resistance required is:", "explanation": "To convert a galvanometer to an ammeter, a shunt resistance S is connected in parallel. Using the formula S = Ig x G/(I - Ig), where Ig = 1 mA = 0.001 A, G = 50 Ω, and I = 5 A: S = 0.001 x 50 / (5 - 0.001) = 0.05 / 4.999 ≈ 0.01 Ω. Since Ig << I, we can approximate S ≈ Ig x G / I = 0.001 x 50 / 5 = 0.01 Ω.", "correct_answer": "A", "concept_tags": ["galvanometer-to-ammeter", "shunt-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-devices-06", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 Ω", "is_correct": true}, {"key": "B", "text": "0.05 Ω", "is_correct": false}, {"key": "C", "text": "1.0 Ω", "is_correct": false}, {"key": "D", "text": "50 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "0.05 Ω = Ig x G = 0.001 x 50. This is the numerator of the formula but you must divide by (I - Ig) ≈ 5 to get the shunt value.", "misconception": "Using S = Ig x G instead of the complete formula S = Ig x G/(I - Ig)"}, {"option_key": "C", "hint": "1.0 Ω is too high for a shunt. The shunt must be much smaller than the galvanometer resistance to divert most current away from the coil.", "misconception": "Not understanding that shunt resistance should be very small"}, {"option_key": "D", "hint": "Using S = G = 50 Ω means equal resistance in parallel, which would only double the range, not increase it 5000 times.", "misconception": "Thinking the shunt should equal the galvanometer resistance"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current sensitivity of a moving coil galvanometer can be increased by:", "explanation": "Current sensitivity Is = NAB/k, where N is the number of turns, A is the area of the coil, B is the magnetic field strength, and k is the torsional spring constant. To increase current sensitivity, we can increase N, A, or B, or decrease k (use a weaker spring). Increasing the spring constant k would decrease the sensitivity, not increase it.", "correct_answer": "C", "concept_tags": ["current-sensitivity", "galvanometer", "NAB-by-k"], "payload": {"question_id": "cuet-phy-magmov-devices-07", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "understand", "options": [{"key": "A", "text": "Increasing the spring constant k", "is_correct": false}, {"key": "B", "text": "Decreasing the number of turns N", "is_correct": false}, {"key": "C", "text": "Increasing the magnetic field strength B", "is_correct": true}, {"key": "D", "text": "Decreasing the area of the coil A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since Is = NAB/k, increasing k (denominator) would decrease the sensitivity, making the galvanometer less sensitive to small currents.", "misconception": "Confusing direct and inverse proportionality in the sensitivity formula"}, {"option_key": "B", "hint": "N appears in the numerator of Is = NAB/k. Decreasing N would reduce sensitivity, not increase it.", "misconception": "Incorrectly identifying N as being in the denominator"}, {"option_key": "D", "hint": "Area A is in the numerator of Is = NAB/k. A larger coil area increases the torque for a given current, increasing sensitivity.", "misconception": "Thinking smaller area gives better sensitivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer of resistance 100 Ω gives full-scale deflection for a current of 10 mA. The resistance to be connected in series to convert it into a voltmeter of range 0-100 V is:", "explanation": "To convert a galvanometer to a voltmeter, a high resistance R is connected in series. Using R = V/Ig - G, where V = 100 V, Ig = 10 mA = 0.01 A, and G = 100 Ω: R = 100/0.01 - 100 = 10000 - 100 = 9900 Ω. The total resistance of the voltmeter becomes G + R = 10000 Ω, ensuring that only Ig flows when V is applied across it.", "correct_answer": "D", "concept_tags": ["galvanometer-to-voltmeter", "series-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-devices-08", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "10000 Ω", "is_correct": false}, {"key": "B", "text": "1000 Ω", "is_correct": false}, {"key": "C", "text": "10 Ω", "is_correct": false}, {"key": "D", "text": "9900 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10000 Ω is V/Ig = 100/0.01, which is the total resistance needed. But the question asks for the series resistance R alone, so you must subtract G: R = 10000 - 100 = 9900 Ω.", "misconception": "Forgetting to subtract the galvanometer resistance G from V/Ig"}, {"option_key": "B", "hint": "1000 Ω would give a total resistance of 1100 Ω, limiting the voltmeter range to only V = Ig x (G + R) = 0.01 x 1100 = 11 V, not 100 V.", "misconception": "Arithmetic error or using wrong formula"}, {"option_key": "C", "hint": "10 Ω is far too small. With R = 10 Ω, total resistance = 110 Ω, giving range V = 0.01 x 110 = 1.1 V only.", "misconception": "Confusing voltmeter conversion with ammeter conversion (where low resistance is used)"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The maximum kinetic energy of a charged particle emerging from a cyclotron of radius R, magnetic field B, charge q, and mass m is:", "explanation": "In a cyclotron, the charged particle moves in a circular path where the magnetic force provides centripetal force: qvB = mv^2/R, giving v = qBR/m. The maximum kinetic energy is KE = (1/2)mv^2 = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m). Here R is the radius of the largest semicircular path (the dee radius).", "correct_answer": "A", "concept_tags": ["cyclotron", "kinetic-energy", "maximum-energy", "dee-radius"], "payload": {"question_id": "cuet-phy-magmov-devices-09", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "q²B²R²/(2m)", "is_correct": true}, {"key": "B", "text": "qBR/(2m)", "is_correct": false}, {"key": "C", "text": "q²B²R²/(m)", "is_correct": false}, {"key": "D", "text": "qB²R²/(2m)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This expression has dimensions of velocity (m/s), not energy (kg m^2/s^2). The kinetic energy must involve squared terms of q, B, and R.", "misconception": "Confusing the expression for velocity with kinetic energy"}, {"option_key": "C", "hint": "This is twice the correct answer. KE = (1/2)mv^2 has the factor of 1/2, so the result should be q^2B^2R^2/(2m), not q^2B^2R^2/m.", "misconception": "Forgetting the factor of 1/2 in the kinetic energy formula"}, {"option_key": "D", "hint": "This expression is missing one factor of q. Since v = qBR/m, the KE = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m), requiring q squared.", "misconception": "Error in squaring the velocity expression"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The voltage sensitivity of a galvanometer of resistance G, having N turns of area A in magnetic field B with spring constant k is given by:", "explanation": "Voltage sensitivity Vs = deflection per unit voltage = θ/V. Since θ/I (current sensitivity) = NAB/k, and V = IR (where R is the total resistance = G for the galvanometer alone), we get Vs = θ/V = (θ/I) x (1/G) = NAB/(kG). Thus voltage sensitivity depends inversely on the galvanometer resistance, unlike current sensitivity.", "correct_answer": "C", "concept_tags": ["voltage-sensitivity", "galvanometer", "NAB-by-kG"], "payload": {"question_id": "cuet-phy-magmov-devices-10", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "understand", "options": [{"key": "A", "text": "NAB/k", "is_correct": false}, {"key": "B", "text": "NABk/G", "is_correct": false}, {"key": "C", "text": "NAB/(kG)", "is_correct": true}, {"key": "D", "text": "NAG/(kB)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "NAB/k is the current sensitivity (θ/I), not the voltage sensitivity. Voltage sensitivity = current sensitivity / G = NAB/(kG).", "misconception": "Confusing current sensitivity with voltage sensitivity"}, {"option_key": "B", "hint": "This expression has k in the numerator. Since higher spring constant k means lower deflection per unit current, k must be in the denominator.", "misconception": "Placing k incorrectly in the formula"}, {"option_key": "D", "hint": "This expression has G in the numerator and B in the denominator, both of which are inverted. Higher B gives more torque (hence more sensitivity), and higher G gives less voltage sensitivity.", "misconception": "Swapping the positions of B and G"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton is accelerated in a cyclotron with magnetic field 1.5 T. The radius of the dees is 0.5 m. The maximum kinetic energy gained by the proton is approximately (mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C):", "explanation": "Maximum KE = q^2B^2R^2/(2m). Substituting: KE = (1.6 x 10^-19)^2 x (1.5)^2 x (0.5)^2 / (2 x 1.67 x 10^-27) = (2.56 x 10^-38) x 2.25 x 0.25 / (3.34 x 10^-27) = (2.56 x 10^-38 x 0.5625) / (3.34 x 10^-27) = 1.44 x 10^-38 / 3.34 x 10^-27 = 4.31 x 10^-12 J. Converting to MeV: 4.31 x 10^-12 / 1.6 x 10^-13 ≈ 26.9 MeV ≈ 27 MeV.", "correct_answer": "C", "concept_tags": ["cyclotron", "maximum-kinetic-energy", "proton", "numerical-calculation"], "payload": {"question_id": "cuet-phy-magmov-devices-11", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "7 MeV", "is_correct": false}, {"key": "B", "text": "14 MeV", "is_correct": false}, {"key": "C", "text": "27 MeV", "is_correct": true}, {"key": "D", "text": "54 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "7 MeV is approximately 1/4 of the correct answer. Check if you used R = 0.25 m instead of 0.5 m, or missed squaring one of the terms.", "misconception": "Using R instead of R^2 in the kinetic energy formula"}, {"option_key": "B", "hint": "14 MeV is half the correct answer. Ensure you have squared both q and B correctly in q^2B^2R^2/(2m).", "misconception": "Forgetting to square one of the quantities"}, {"option_key": "D", "hint": "54 MeV is double the correct answer. Check that you included the factor of 2 in the denominator of KE = q^2B^2R^2/(2m).", "misconception": "Forgetting the factor of 1/2 in the kinetic energy expression"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer of resistance 50 Ω and full-scale deflection current 2 mA is to be converted into an ammeter of range 0-10 A and a voltmeter of range 0-200 V. The ratio of shunt resistance to series resistance is:", "explanation": "For ammeter: S = Ig x G/(I - Ig) = 0.002 x 50/(10 - 0.002) ≈ 0.1/9.998 ≈ 0.01 Ω. For voltmeter: R = V/Ig - G = 200/0.002 - 50 = 100000 - 50 = 99950 Ω. Ratio S/R = 0.01/99950 ≈ 1 x 10^-7. Alternatively, S/R = [Ig x G/(I - Ig)] / [V/Ig - G] ≈ [Ig x G/I] / [V/Ig] = Ig^2 x G / (IV) = (0.002)^2 x 50 / (10 x 200) = 2 x 10^-7 / 2000 = 1 x 10^-7.", "correct_answer": "D", "concept_tags": ["ammeter-voltmeter-conversion", "shunt", "series-resistance", "ratio"], "payload": {"question_id": "cuet-phy-magmov-devices-12", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 x 10^-3", "is_correct": false}, {"key": "B", "text": "1 x 10^-5", "is_correct": false}, {"key": "C", "text": "1 x 10^-6", "is_correct": false}, {"key": "D", "text": "1 x 10^-7", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would imply the shunt is only 1000 times smaller than the series resistance. Given the huge difference in conversion (ammeter needs ~0.01 Ω, voltmeter needs ~100000 Ω), the ratio should be much smaller.", "misconception": "Rough estimation without proper calculation"}, {"option_key": "B", "hint": "Verify your calculation: S ≈ 0.01 Ω and R ≈ 99950 Ω. The ratio 0.01/99950 is approximately 10^-7, not 10^-5.", "misconception": "Arithmetic error in the order of magnitude"}, {"option_key": "C", "hint": "Close but off by a factor of 10. Carefully recalculate: S/R = 0.01/99950 ≈ 1.0 x 10^-7.", "misconception": "Small arithmetic or rounding error"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The cyclotron frequency does not depend on the speed of the charged particle. Reason (R): In a cyclotron, as the particle gains speed, the radius of its circular path increases proportionally, keeping the time period constant.", "explanation": "Both the Assertion and Reason are correct, and the Reason correctly explains the Assertion. The cyclotron frequency f = qB/(2πm) is independent of speed. This is because when a particle gains energy and moves faster (v increases), it moves to a larger radius orbit (r = mv/(qB)), so r increases proportionally with v. Since T = 2πr/v = 2πm/(qB), the v cancels out, making the period constant. This is the fundamental principle that allows the cyclotron to use a fixed-frequency oscillating electric field.", "correct_answer": "A", "concept_tags": ["cyclotron-frequency", "radius-speed-relation", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-magmov-devices-13", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly explains why the frequency is independent of speed: the increase in radius exactly compensates for the increase in speed, so the time per revolution stays constant. This is a causal explanation.", "misconception": "Not recognizing the causal connection between the radius-speed relationship and constant frequency"}, {"option_key": "C", "hint": "The Reason is factually correct. In a cyclotron, r = mv/(qB), so r is directly proportional to v. The circumference (2πr) grows in proportion to v, keeping T = 2πr/v constant.", "misconception": "Doubting the relationship between radius and speed"}, {"option_key": "D", "hint": "The Assertion is correct: from f = qB/(2πm), the frequency clearly does not contain velocity v, confirming it is independent of speed.", "misconception": "Thinking cyclotron frequency depends on speed"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Increasing the number of turns in a moving coil galvanometer always increases both its current sensitivity and voltage sensitivity. Reason (R): Current sensitivity is NAB/k and voltage sensitivity is NAB/(kG), and increasing N increases the resistance G of the coil.", "explanation": "The Assertion is incorrect. While increasing N does increase current sensitivity (Is = NAB/k), it also increases the coil resistance G (since G is proportional to N for a given wire). Voltage sensitivity Vs = NAB/(kG) = Is/G. As N increases, both NAB/k and G increase, and the net effect on Vs depends on the relative rates. In fact, since G is proportional to N (longer wire), Vs = NAB/(kG) may remain roughly constant or even decrease. So increasing N does NOT always increase voltage sensitivity. The Reason is correct: it correctly states both formulas and that increasing N increases G.", "correct_answer": "D", "concept_tags": ["current-sensitivity", "voltage-sensitivity", "number-of-turns", "galvanometer-design"], "payload": {"question_id": "cuet-phy-magmov-devices-14", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The Assertion claims increasing N always increases both sensitivities. But since G also increases with N, voltage sensitivity Vs = NAB/(kG) may not increase. The Assertion is therefore incorrect.", "misconception": "Ignoring the effect of increased resistance when adding more turns"}, {"option_key": "B", "hint": "Since the Assertion is incorrect (voltage sensitivity does not necessarily increase with N), options involving ''A is correct'' cannot be right.", "misconception": "Not analyzing the voltage sensitivity formula carefully"}, {"option_key": "C", "hint": "The Reason correctly states the formulas and the fact that G increases with N. This is physically accurate since more turns mean longer wire and greater resistance.", "misconception": "Thinking the Reason is wrong about resistance increasing with turns"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Cyclotron frequency\n(Q) Shunt resistance for ammeter\n(R) Series resistance for voltmeter\n(S) Current sensitivity of galvanometer\n\nColumn II:\n(1) NAB/k\n(2) V/Ig - G\n(3) qB/(2πm)\n(4) Ig·G/(I - Ig)", "explanation": "P-3: Cyclotron frequency f = qB/(2πm). Q-4: Shunt resistance S = Ig·G/(I - Ig) for converting galvanometer to ammeter. R-2: Series resistance R = V/Ig - G for converting galvanometer to voltmeter. S-1: Current sensitivity = NAB/k, which is the deflection per unit current in a galvanometer.", "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "ammeter-conversion", "voltmeter-conversion", "current-sensitivity", "match-the-following"], "payload": {"question_id": "cuet-phy-magmov-devices-15", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "understand", "options": [{"key": "A", "text": "P-3, Q-2, R-4, S-1", "is_correct": false}, {"key": "B", "text": "P-3, Q-4, R-2, S-1", "is_correct": true}, {"key": "C", "text": "P-4, Q-3, R-1, S-2", "is_correct": false}, {"key": "D", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps Q and R. The shunt resistance formula contains Ig·G/(I - Ig) which is (4), while the series resistance formula is V/Ig - G which is (2). So Q matches 4, not 2.", "misconception": "Swapping the ammeter and voltmeter conversion formulas"}, {"option_key": "C", "hint": "P-4 would match cyclotron frequency to the shunt formula, which is dimensionally inconsistent. Cyclotron frequency has units of Hz = 1/s, while Ig·G/(I-Ig) has units of Ω.", "misconception": "Not checking dimensional consistency of the formulas"}, {"option_key": "D", "hint": "P-1 matches cyclotron frequency with NAB/k, which is the current sensitivity formula. Cyclotron frequency f = qB/(2πm) matches with (3).", "misconception": "Confusing cyclotron frequency with galvanometer sensitivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field inside a long solenoid\n(Q) Magnetic field of a toroid (inside)\n(R) Cyclotron maximum KE\n(S) Deflecting torque in a galvanometer\n\nColumn II:\n(1) NIAB\n(2) μ₀nI (n = turns per unit length)\n(3) q²B²R²/(2m)\n(4) μ₀NI/(2πr)", "explanation": "P-2: The magnetic field inside a long solenoid is B = μ₀nI, where n is the number of turns per unit length. Q-4: Inside a toroid, B = μ₀NI/(2πr), where N is total turns and r is the radius of the toroidal path. R-3: Maximum kinetic energy from a cyclotron is q²B²R²/(2m). S-1: The deflecting torque on the coil in a galvanometer is τ = NIAB.", "correct_answer": "A", "concept_tags": ["solenoid", "toroid", "cyclotron-energy", "galvanometer-torque", "match-the-following"], "payload": {"question_id": "cuet-phy-magmov-devices-16", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-4, R-3, S-1", "is_correct": true}, {"key": "B", "text": "P-4, Q-2, R-3, S-1", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": false}, {"key": "D", "text": "P-2, Q-1, R-3, S-4", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This swaps P and Q. The solenoid field B = μ₀nI uses turns per unit length (n), while the toroid field B = μ₀NI/(2πr) uses total turns N and has r in the denominator.", "misconception": "Confusing the solenoid and toroid magnetic field formulas"}, {"option_key": "C", "hint": "R-1 would match cyclotron KE with NIAB (torque). The cyclotron KE expression q²B²R²/(2m) is (3), and NIAB is the galvanometer torque (1).", "misconception": "Swapping the cyclotron energy and galvanometer torque expressions"}, {"option_key": "D", "hint": "Q-1 would match toroid field with NIAB, which is the torque expression for a galvanometer. The toroid field is μ₀NI/(2πr), which is (4).", "misconception": "Not distinguishing between the torque formula and the toroid field formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside a solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This statement is TRUE. Inside a long solenoid (ideal case), the magnetic field is uniform in both magnitude and direction. The field lines run parallel to the axis of the solenoid. This can be derived using Ampere''s law, which gives B = μ₀nI inside the solenoid (where n = N/L is the number of turns per unit length). Outside the solenoid, the field is approximately zero.", "correct_answer": "A", "concept_tags": ["solenoid", "uniform-magnetic-field", "field-direction"], "payload": {"question_id": "cuet-phy-magmov-devices-17", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The field inside an ideal long solenoid is indeed uniform and axial. This is a standard result from Ampere''s law applied to a rectangular Amperian loop.", "misconception": "Confusing solenoid field with that of a bar magnet, where the field is non-uniform"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A cyclotron can be used to accelerate electrons to high energies efficiently.", "explanation": "This statement is FALSE. A cyclotron cannot efficiently accelerate electrons because electrons have very small mass (9.1 x 10^-31 kg). Due to their low mass, electrons quickly reach relativistic speeds, at which point their mass increases significantly (relativistic mass increase). This causes the cyclotron frequency f = qB/(2πm) to decrease, and the particles go out of synchronization with the fixed-frequency oscillating electric field. This is a well-known limitation of the cyclotron.", "correct_answer": "B", "concept_tags": ["cyclotron", "electrons", "relativistic-effects", "limitation"], "payload": {"question_id": "cuet-phy-magmov-devices-18", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small rest mass, so they reach relativistic speeds at relatively low energies. At relativistic speeds, the effective mass increases, changing the cyclotron frequency and causing loss of synchronization.", "misconception": "Thinking the cyclotron works for all charged particles without considering relativistic effects"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "In a moving coil galvanometer, a radial magnetic field is produced by using concave-shaped pole pieces and a _____ placed inside the coil.", "explanation": "A soft iron core is placed inside the coil of a moving coil galvanometer. The soft iron core, along with the concave-shaped (cylindrical) pole pieces of the permanent magnet, creates a radial magnetic field. In a radial field, the plane of the coil is always parallel to the magnetic field direction, so the torque τ = NIAB sin(90°) = NIAB for all angular positions. This ensures a linear relationship between the current and the deflection angle (θ ∝ I).", "correct_answer": "C", "concept_tags": ["moving-coil-galvanometer", "radial-field", "soft-iron-core", "construction"], "payload": {"question_id": "cuet-phy-magmov-devices-19", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "Hard iron core", "is_correct": false}, {"key": "B", "text": "Copper cylinder", "is_correct": false}, {"key": "C", "text": "Soft iron core", "is_correct": true}, {"key": "D", "text": "Permanent magnet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Hard iron retains magnetism (used for permanent magnets) and is not suitable for the core. Soft iron is used because it has high permeability, low retentivity, and strengthens the radial field without permanent magnetization.", "misconception": "Confusing soft iron (high permeability, low retentivity) with hard iron (permanent magnets)"}, {"option_key": "B", "hint": "A copper cylinder is not used as the core. Copper is non-magnetic and would not help in creating a radial magnetic field. Soft iron''s high magnetic permeability is essential for concentrating field lines.", "misconception": "Confusing copper damping mechanism with the iron core"}, {"option_key": "D", "hint": "The permanent magnet provides the external magnetic field and is located outside the coil (as pole pieces). The core inside the coil is soft iron, which helps make this external field radial.", "misconception": "Confusing the location and role of the permanent magnet with the core"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A medical research lab uses a cyclotron to produce radioactive isotopes for PET (Positron Emission Tomography) scans. The cyclotron accelerates protons using a magnetic field of 2.0 T. The protons are extracted when they reach a radius of 0.4 m from the centre. If the cyclotron''s oscillating electric field operates at a fixed frequency, what is the frequency of the oscillating electric field, and what is the kinetic energy of the extracted protons? (Given: mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C)", "explanation": "The cyclotron frequency f = qB/(2πm) = (1.6 x 10^-19 x 2.0)/(2π x 1.67 x 10^-27) = 3.2 x 10^-19 / (1.049 x 10^-26) = 3.05 x 10^7 Hz ≈ 30.5 MHz. The maximum kinetic energy KE = q²B²R²/(2m) = (1.6 x 10^-19)² x (2.0)² x (0.4)² / (2 x 1.67 x 10^-27) = (2.56 x 10^-38 x 4 x 0.16) / (3.34 x 10^-27) = 1.638 x 10^-38 / 3.34 x 10^-27 = 4.9 x 10^-12 J. Converting: 4.9 x 10^-12 / 1.6 x 10^-13 ≈ 30.6 MeV. So the frequency is approximately 30.5 MHz and KE is approximately 30.6 MeV.", "correct_answer": "B", "concept_tags": ["cyclotron", "frequency", "kinetic-energy", "PET-scan", "medical-application", "numerical"], "payload": {"question_id": "cuet-phy-magmov-devices-20", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "Frequency ≈ 15.2 MHz, KE ≈ 15 MeV", "is_correct": false}, {"key": "B", "text": "Frequency ≈ 30.5 MHz, KE ≈ 30.6 MeV", "is_correct": true}, {"key": "C", "text": "Frequency ≈ 30.5 MHz, KE ≈ 61 MeV", "is_correct": false}, {"key": "D", "text": "Frequency ≈ 61 MHz, KE ≈ 30.6 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "15.2 MHz is half the correct frequency. Check your calculation: f = qB/(2πm). With B = 2.0 T, the numerator is qB = 3.2 x 10^-19, not 1.6 x 10^-19. Ensure you use B = 2.0 T, not 1.0 T.", "misconception": "Using B = 1.0 T instead of 2.0 T in the frequency formula"}, {"option_key": "C", "hint": "The frequency is correct at 30.5 MHz, but 61 MeV is double the actual KE. Verify the factor of 2 in the denominator: KE = q²B²R²/(2m), not q²B²R²/m.", "misconception": "Forgetting the factor of 2 in the kinetic energy denominator"}, {"option_key": "D", "hint": "61 MHz is double the correct frequency. The formula is f = qB/(2πm), and 2π ≈ 6.28, not π ≈ 3.14. Using π instead of 2π would give the wrong answer.", "misconception": "Using π instead of 2π in the cyclotron frequency formula"}]}}]'::jsonb, 'deploy-2026-03-05-b13');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A charged particle moving with velocity v enters a uniform magnetic field B perpendicular to its velocity. The magnetic force on the particle is:", "explanation": "The magnetic force on a moving charged particle is given by F = qv × B. When the velocity is perpendicular to the magnetic field (θ = 90°), sin 90° = 1, so F = qvB. This is the maximum force the magnetic field can exert on the charge.", "correct_answer": "A", "concept_tags": ["lorentz-force", "magnetic-force", "moving-charge"], "payload": {"question_id": "cuet-phy-magmov-force-01", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "remember", "options": [{"key": "A", "text": "qvB", "is_correct": true}, {"key": "B", "text": "qvB/2", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "qv/B", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The factor of 1/2 does not appear in the Lorentz force formula. F = qvB sinθ has no such coefficient.", "misconception": "Confusing with kinetic energy formula which has a 1/2 factor"}, {"option_key": "C", "hint": "Force is zero only when the charge moves parallel to B (θ = 0°). Here the motion is perpendicular to B, so sinθ = 1.", "misconception": "Confusing perpendicular and parallel motion relative to B"}, {"option_key": "D", "hint": "Dimensionally, qv/B gives C·m/(s·T) which does not have units of force. The correct formula has B in the numerator.", "misconception": "Incorrectly placing B in the denominator"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A proton moves parallel to a uniform magnetic field. The force acting on the proton is:", "explanation": "The magnetic force on a charged particle is F = qvB sinθ. When the particle moves parallel to B, the angle θ = 0°, and sin 0° = 0. Therefore, F = 0. A magnetic field exerts no force on a charge moving along the field direction.", "correct_answer": "B", "concept_tags": ["magnetic-force", "parallel-motion", "zero-force"], "payload": {"question_id": "cuet-phy-magmov-force-02", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "understand", "options": [{"key": "A", "text": "qvB", "is_correct": false}, {"key": "B", "text": "Zero", "is_correct": true}, {"key": "C", "text": "qvB/2", "is_correct": false}, {"key": "D", "text": "qB/v", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "F = qvB applies only when v is perpendicular to B (θ = 90°). Here the motion is parallel, so sinθ = 0.", "misconception": "Ignoring the sinθ dependence in the Lorentz force"}, {"option_key": "C", "hint": "There is no 1/2 factor in the force formula, and regardless the force is zero when velocity is parallel to B.", "misconception": null}, {"option_key": "D", "hint": "This expression is dimensionally incorrect for force and does not correspond to any known formula.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The work done by a magnetic force on a charged particle moving in a magnetic field is:", "explanation": "The magnetic force F = qv × B is always perpendicular to the velocity of the charged particle. Since work done W = F · ds = F · v dt, and F is perpendicular to v, the dot product F · v = 0. Hence, the magnetic force does no work on a moving charge. It can only change the direction of velocity, not its magnitude.", "correct_answer": "C", "concept_tags": ["work-done", "magnetic-force", "perpendicular-force"], "payload": {"question_id": "cuet-phy-magmov-force-03", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "understand", "options": [{"key": "A", "text": "Positive", "is_correct": false}, {"key": "B", "text": "Negative", "is_correct": false}, {"key": "C", "text": "Always zero", "is_correct": true}, {"key": "D", "text": "Depends on the magnitude of charge", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Magnetic force is always perpendicular to velocity. A perpendicular force cannot increase the kinetic energy or do positive work.", "misconception": "Assuming any force that acts on a moving particle does work"}, {"option_key": "B", "hint": "Negative work would slow down the particle. But the speed of a charged particle in a pure magnetic field remains constant.", "misconception": "Confusing magnetic force with a drag or resistive force"}, {"option_key": "D", "hint": "Regardless of the magnitude of charge, the magnetic force is always perpendicular to displacement, so work is always zero.", "misconception": "Thinking work depends on charge magnitude alone"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Two long parallel conductors carry currents in the same direction. The force between them is:", "explanation": "When two parallel conductors carry currents in the same direction, the magnetic field produced by one conductor at the location of the other results in an attractive force between them. This can be verified using the right-hand rule: the field from one wire at the other wire''s location creates a force directed toward the first wire. Currents in opposite directions repel each other.", "correct_answer": "A", "concept_tags": ["parallel-conductors", "force-between-conductors", "attractive-force"], "payload": {"question_id": "cuet-phy-magmov-force-04", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "remember", "options": [{"key": "A", "text": "Attractive", "is_correct": true}, {"key": "B", "text": "Repulsive", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "Attractive or repulsive depending on the magnitude of currents", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Repulsive force occurs between parallel conductors carrying currents in opposite directions. Same-direction currents always attract.", "misconception": "Confusing same-direction and opposite-direction current rules"}, {"option_key": "C", "hint": "Two current-carrying conductors always exert a force on each other. The force is zero only when one of the currents is zero.", "misconception": "Thinking parallel conductors do not interact magnetically"}, {"option_key": "D", "hint": "The nature of the force (attractive/repulsive) depends only on the relative direction of currents, not on their magnitudes.", "misconception": "Confusing the nature of force with its magnitude"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A proton (mass 1.67 × 10⁻²⁷ kg) moves with a speed of 5 × 10⁶ m/s perpendicular to a magnetic field of 0.5 T. The radius of the circular path described by the proton is (charge of proton = 1.6 × 10⁻¹⁹ C):", "explanation": "When a charged particle moves perpendicular to a magnetic field, it follows a circular path. The radius is given by r = mv/(qB). Substituting: r = (1.67 × 10⁻²⁷ × 5 × 10⁶) / (1.6 × 10⁻¹⁹ × 0.5) = (8.35 × 10⁻²¹) / (8.0 × 10⁻²⁰) = 0.104 m ≈ 0.1 m.", "correct_answer": "B", "concept_tags": ["circular-motion", "radius-of-path", "proton", "magnetic-field"], "payload": {"question_id": "cuet-phy-magmov-force-05", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 m", "is_correct": false}, {"key": "B", "text": "0.1 m", "is_correct": true}, {"key": "C", "text": "1.0 m", "is_correct": false}, {"key": "D", "text": "0.05 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Re-check the calculation: r = mv/(qB) = (1.67 × 10⁻²⁷ × 5 × 10⁶)/(1.6 × 10⁻¹⁹ × 0.5) ≈ 0.1 m.", "misconception": "Arithmetic error in power-of-ten calculation"}, {"option_key": "C", "hint": "1.0 m is ten times the correct answer. Ensure proper handling of exponents in the numerator and denominator.", "misconception": "Arithmetic error in power-of-ten calculation"}, {"option_key": "D", "hint": "0.05 m results from an incorrect factor of 2. The formula r = mv/(qB) does not include any additional numerical factor.", "misconception": "Introducing an extraneous factor in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron (charge e, mass m) and a proton (charge e, mass M) enter a uniform magnetic field perpendicularly with the same kinetic energy. The ratio of radii of their circular paths (rₑ/rₚ) is:", "explanation": "The radius of circular motion in a magnetic field is r = mv/(eB). Since kinetic energy K = ½mv², we get v = √(2K/m), so r = m√(2K/m)/(eB) = √(2mK)/(eB). Therefore rₑ/rₚ = √(m/M). Since the electron mass m is much smaller than proton mass M, the electron follows a much smaller circle.", "correct_answer": "C", "concept_tags": ["radius-ratio", "kinetic-energy", "electron", "proton", "circular-motion"], "payload": {"question_id": "cuet-phy-magmov-force-06", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "analyze", "options": [{"key": "A", "text": "m/M", "is_correct": false}, {"key": "B", "text": "M/m", "is_correct": false}, {"key": "C", "text": "√(m/M)", "is_correct": true}, {"key": "D", "text": "√(M/m)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the ratio if r were directly proportional to mass (at same velocity). But at same kinetic energy, r = √(2mK)/(eB), giving a square-root dependence.", "misconception": "Using r = mv/(qB) without converting velocity in terms of kinetic energy"}, {"option_key": "B", "hint": "M/m > 1 would mean the electron has a larger radius than the proton, which contradicts the fact that the lighter particle has a smaller radius at equal KE.", "misconception": "Inverting the mass ratio"}, {"option_key": "D", "hint": "√(M/m) > 1 would imply rₑ > rₚ. Since the electron is lighter, it has less momentum at the same KE and hence a smaller radius.", "misconception": "Confusing which particle has the larger radius"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A straight conductor of length 0.5 m carrying a current of 2 A is placed in a uniform magnetic field of 0.4 T at an angle of 30° to the field. The force on the conductor is:", "explanation": "The force on a current-carrying conductor in a magnetic field is F = BIL sinθ. Substituting the given values: F = 0.4 × 2 × 0.5 × sin 30° = 0.4 × 2 × 0.5 × 0.5 = 0.2 N.", "correct_answer": "D", "concept_tags": ["force-on-conductor", "current-carrying-conductor", "magnetic-field", "numerical"], "payload": {"question_id": "cuet-phy-magmov-force-07", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "apply", "options": [{"key": "A", "text": "0.4 N", "is_correct": false}, {"key": "B", "text": "0.1 N", "is_correct": false}, {"key": "C", "text": "0.8 N", "is_correct": false}, {"key": "D", "text": "0.2 N", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.4 N would be the answer if sinθ = 1 (θ = 90°). Here θ = 30°, so sin 30° = 0.5 must be included.", "misconception": "Forgetting the sinθ factor when the conductor is not perpendicular to B"}, {"option_key": "B", "hint": "0.1 N would result from using sin 30° twice or an arithmetic error. Check: F = 0.4 × 2 × 0.5 × 0.5 = 0.2 N.", "misconception": "Arithmetic error in multiplication"}, {"option_key": "C", "hint": "0.8 N would result from ignoring sin 30° and also doubling the result. F = BIL sinθ, not 2BIL.", "misconception": "Using an incorrect formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a velocity selector, a charged particle passes undeflected when:", "explanation": "In a velocity selector, crossed electric (E) and magnetic (B) fields are applied. The electric force qE and the magnetic force qvB act in opposite directions. The particle passes undeflected when these forces balance: qE = qvB, giving v = E/B. This condition is independent of the charge and mass of the particle.", "correct_answer": "C", "concept_tags": ["velocity-selector", "electric-field", "magnetic-field", "undeflected"], "payload": {"question_id": "cuet-phy-magmov-force-08", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "understand", "options": [{"key": "A", "text": "v = B/E", "is_correct": false}, {"key": "B", "text": "v = EB", "is_correct": false}, {"key": "C", "text": "v = E/B", "is_correct": true}, {"key": "D", "text": "v = E²/B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "B/E is the inverse of the correct answer. From qE = qvB, solving for v gives v = E/B, not B/E.", "misconception": "Inverting the ratio while solving qE = qvB"}, {"option_key": "B", "hint": "EB is dimensionally incorrect for velocity. E has units V/m and B has units T, so EB would have units V·T/m, not m/s.", "misconception": "Incorrectly combining E and B"}, {"option_key": "D", "hint": "E²/B does not follow from balancing electric and magnetic forces. The correct derivation gives v = E/B.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charged particle moves in a helical path in a uniform magnetic field. This happens when the velocity of the particle:", "explanation": "When a charged particle enters a magnetic field with its velocity at an angle to the field (neither parallel nor perpendicular), the velocity component perpendicular to B causes circular motion while the component parallel to B remains unaffected. The combination of circular motion and uniform linear motion along B produces a helical (spiral) path.", "correct_answer": "D", "concept_tags": ["helical-motion", "velocity-components", "magnetic-field"], "payload": {"question_id": "cuet-phy-magmov-force-09", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "understand", "options": [{"key": "A", "text": "Is perpendicular to B", "is_correct": false}, {"key": "B", "text": "Is parallel to B", "is_correct": false}, {"key": "C", "text": "Is zero", "is_correct": false}, {"key": "D", "text": "Has components both parallel and perpendicular to B", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "When velocity is purely perpendicular to B, the particle follows a circular path, not a helical one.", "misconception": "Confusing circular and helical paths"}, {"option_key": "B", "hint": "When velocity is parallel to B, there is no magnetic force and the particle moves in a straight line.", "misconception": "Not recognizing that parallel motion produces zero force"}, {"option_key": "C", "hint": "If velocity is zero, there is no motion at all and hence no path of any kind.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The force per unit length between two long parallel conductors carrying currents I₁ and I₂ separated by a distance d is given by:", "explanation": "The magnetic field produced by conductor 1 at the location of conductor 2 is B₁ = μ₀I₁/(2πd). The force per unit length on conductor 2 is F/L = B₁I₂ = μ₀I₁I₂/(2πd). This expression is fundamental and is used to define the SI unit of current (ampere).", "correct_answer": "B", "concept_tags": ["force-per-unit-length", "parallel-conductors", "ampere-definition"], "payload": {"question_id": "cuet-phy-magmov-force-10", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I₁I₂/(4πd)", "is_correct": false}, {"key": "B", "text": "μ₀I₁I₂/(2πd)", "is_correct": true}, {"key": "C", "text": "μ₀I₁I₂/(2πd²)", "is_correct": false}, {"key": "D", "text": "μ₀I₁I₂d/(2π)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The factor is 2π in the denominator, not 4π. The field of a long wire is B = μ₀I/(2πd), and force/length = BI₂ = μ₀I₁I₂/(2πd).", "misconception": "Confusing 2π (Biot-Savart for infinite wire) with 4π (Coulomb''s law constant)"}, {"option_key": "C", "hint": "The distance d appears to the first power, not squared. This is not an inverse-square law like Coulomb''s law.", "misconception": "Incorrectly applying inverse-square law to magnetic force between wires"}, {"option_key": "D", "hint": "Having d in the numerator would mean force increases with distance, which is physically incorrect. Force decreases as conductors are moved apart.", "misconception": "Placing d in the wrong part of the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An alpha particle (charge 2e, mass 4mₚ) and a proton (charge e, mass mₚ) are accelerated from rest through the same potential difference and then enter a uniform magnetic field perpendicular to their velocity. The ratio of the radii of their circular paths (rα/rₚ) is:", "explanation": "After acceleration through potential difference V, kinetic energy K = qV. So Kα = 2eV and Kₚ = eV. The radius of circular motion is r = √(2mK)/(qB). For alpha particle: rα = √(2 × 4mₚ × 2eV)/(2eB) = √(16mₚeV)/(2eB) = 4√(mₚeV)/(2eB). For proton: rₚ = √(2mₚeV)/(eB) = √(2mₚeV)/(eB). Therefore rα/rₚ = [4√(mₚeV)/(2eB)] / [√(2mₚeV)/(eB)] = [4/(2)] × [1/√2] = 2/√2 = √2 = 1:1 × √2. So rα/rₚ = √2.", "correct_answer": "C", "concept_tags": ["alpha-particle", "proton", "radius-ratio", "potential-difference", "circular-motion"], "payload": {"question_id": "cuet-phy-magmov-force-11", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "analyze", "options": [{"key": "A", "text": "1:1", "is_correct": false}, {"key": "B", "text": "2:1", "is_correct": false}, {"key": "C", "text": "√2 : 1", "is_correct": true}, {"key": "D", "text": "1 : √2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1:1 would require identical r values. Since the alpha particle has different mass and charge, r = √(2mK)/(qB) with K = qV gives different radii.", "misconception": "Assuming equal radii for particles accelerated through same potential"}, {"option_key": "B", "hint": "2:1 would result from r ∝ m/q without properly accounting for the velocity gained through the potential difference.", "misconception": "Not correctly relating kinetic energy to the potential difference for different charges"}, {"option_key": "D", "hint": "1:√2 is the inverse of the correct ratio. The alpha particle, with greater momentum, has the larger radius.", "misconception": "Inverting the ratio of radii"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire of length L is bent into a semicircular loop and carries a current I. It is placed in a uniform magnetic field B directed perpendicular to the plane of the loop. The net force on the semicircular wire is:", "explanation": "For a curved wire in a uniform magnetic field, the net force equals the force on a straight wire connecting the two ends of the curve. The semicircular wire of length L has radius r = L/π. The straight-line distance between the two ends (the diameter) is 2r = 2L/π. Therefore, the net force is F = BI × (2L/π) = 2BIL/π. The direction follows from F = IL × B for the equivalent straight conductor.", "correct_answer": "A", "concept_tags": ["semicircular-loop", "net-force", "uniform-field", "equivalent-straight-wire"], "payload": {"question_id": "cuet-phy-magmov-force-12", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "analyze", "options": [{"key": "A", "text": "2BIL/π", "is_correct": true}, {"key": "B", "text": "BIL", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "πBIL", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "BIL would be the force if the entire wire length L were straight and perpendicular to B. But for a semicircle, the effective length is the chord (diameter) = 2L/π.", "misconception": "Using the arc length instead of the chord length for net force"}, {"option_key": "C", "hint": "Zero net force applies to a complete closed loop in a uniform field. A semicircle is not a closed loop, so the net force is not zero.", "misconception": "Confusing semicircular wire with a complete loop"}, {"option_key": "D", "hint": "πBIL greatly overestimates the force. The effective straight-line length is 2L/π, which is shorter than L, not longer.", "misconception": "Using an incorrect geometric relationship"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The kinetic energy of a charged particle moving in a uniform magnetic field remains constant.\nReason (R): The magnetic force on a moving charge is always perpendicular to its velocity.", "explanation": "The assertion is correct: since the magnetic force does no work, the kinetic energy (and hence the speed) of the charged particle remains unchanged. The reason is also correct: F = qv × B is always perpendicular to v by the nature of the cross product. Furthermore, the reason correctly explains the assertion — it is precisely because the force is perpendicular to velocity that no work is done (W = F · ds = 0 when F ⊥ v), and therefore kinetic energy is conserved.", "correct_answer": "A", "concept_tags": ["kinetic-energy", "magnetic-force", "no-work", "perpendicular-force"], "payload": {"question_id": "cuet-phy-magmov-force-13", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A. The perpendicularity of F to v means W = F · v dt = 0, so KE is constant. The causal link is direct.", "misconception": "Failing to see the direct causal connection between perpendicular force and zero work"}, {"option_key": "C", "hint": "The reason is a fundamental property of the cross product (v × B is always perpendicular to v). R is definitely correct.", "misconception": "Doubting the perpendicularity of the magnetic force to velocity"}, {"option_key": "D", "hint": "The assertion is correct — speed and hence KE of a charged particle in a magnetic field do not change. This is experimentally verified.", "misconception": "Thinking magnetic field changes the kinetic energy of a charge"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A current-carrying closed loop placed in a uniform magnetic field experiences a net force of zero.\nReason (R): The force on a current-carrying conductor in a magnetic field is given by F = I(L × B), where L is the length vector of the conductor.", "explanation": "The assertion is correct: for a closed loop in a uniform magnetic field, the net force is the vector sum of forces on all elements, which equals I(∮dL) × B = I × 0 × B = 0, since the line integral of dL around a closed loop is zero. The reason is also correct: F = I(L × B) is indeed the expression for force on a straight current-carrying conductor. However, the reason by itself does not directly explain why the net force on a closed loop is zero — one also needs the fact that ∮dL = 0 for a closed loop in a uniform field. So R is not the complete explanation of A.", "correct_answer": "B", "concept_tags": ["closed-loop", "net-force-zero", "uniform-field", "force-on-conductor"], "payload": {"question_id": "cuet-phy-magmov-force-14", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are correct, R only gives the force formula for a conductor. It does not explain why the sum of all such forces on a closed loop is zero. The explanation requires ∮dL = 0.", "misconception": "Assuming the force formula alone explains the zero net force on a closed loop"}, {"option_key": "C", "hint": "R is indeed correct. F = I(L × B) is the standard expression for force on a current-carrying conductor in a uniform field.", "misconception": "Doubting the validity of the force formula"}, {"option_key": "D", "hint": "A is correct. A closed current loop in a uniform magnetic field has zero net force (though it may experience a torque).", "misconception": "Confusing torque with net force on a loop"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Charged particle moving parallel to B\n(Q) Charged particle moving perpendicular to B\n(R) Charged particle moving at angle θ (0° < θ < 90°) to B\n(S) Charged particle at rest in B\n\nColumn II:\n(1) Helical path\n(2) Circular path\n(3) Straight line (no force)\n(4) No motion", "explanation": "P → 3: When velocity is parallel to B, sinθ = 0, so F = 0 and the particle continues in a straight line. Q → 2: When velocity is perpendicular to B, the constant perpendicular force causes circular motion. R → 1: When velocity has both parallel and perpendicular components to B, the perpendicular component causes circular motion while the parallel component causes linear drift, resulting in a helical path. S → 4: A stationary charge (v = 0) experiences no magnetic force and remains at rest.", "correct_answer": "D", "concept_tags": ["motion-in-magnetic-field", "circular-motion", "helical-motion", "match-the-following"], "payload": {"question_id": "cuet-phy-magmov-force-15", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→2, Q→3, R→1, S→4", "is_correct": false}, {"key": "B", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": false}, {"key": "D", "text": "P→3, Q→2, R→1, S→4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "P→2 is wrong. A particle moving parallel to B experiences zero force and moves in a straight line, not a circle.", "misconception": "Confusing parallel and perpendicular motion in B"}, {"option_key": "B", "hint": "Q→1 is wrong. A particle moving perpendicular to B traces a circle, not a helix. A helix requires a velocity component along B.", "misconception": "Confusing circular and helical paths"}, {"option_key": "C", "hint": "P→4 is wrong. A particle moving parallel to B is not stationary — it continues in a straight line since there is no magnetic force.", "misconception": "Thinking no force means no motion"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) SI unit of magnetic field\n(Q) Force between two parallel conductors carrying 1 A each, separated by 1 m, per unit length\n(R) Radius of circular path of charge q, mass m, speed v in field B\n(S) Condition for a charged particle to pass undeflected through crossed E and B fields\n\nColumn II:\n(1) mv/(qB)\n(2) 2 × 10⁻⁷ N/m\n(3) v = E/B\n(4) Tesla (T)", "explanation": "P → 4: The SI unit of magnetic field is Tesla (T). Q → 2: Using F/L = μ₀I₁I₂/(2πd) with I₁ = I₂ = 1 A, d = 1 m: F/L = (4π × 10⁻⁷ × 1 × 1)/(2π × 1) = 2 × 10⁻⁷ N/m. This is the basis for the definition of the ampere. R → 1: The radius of circular motion is r = mv/(qB), obtained by equating qvB = mv²/r. S → 3: In a velocity selector, qE = qvB gives v = E/B.", "correct_answer": "C", "concept_tags": ["tesla", "ampere-definition", "radius-formula", "velocity-selector", "match-the-following"], "payload": {"question_id": "cuet-phy-magmov-force-16", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→4, Q→1, R→2, S→3", "is_correct": false}, {"key": "B", "text": "P→4, Q→2, R→3, S→1", "is_correct": false}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": true}, {"key": "D", "text": "P→2, Q→4, R→1, S→3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q→1 is wrong. The force per unit length between two wires is a numerical value (2 × 10⁻⁷ N/m), not the expression mv/(qB) which gives the radius of circular motion.", "misconception": "Mixing up the radius formula with the force between parallel conductors"}, {"option_key": "B", "hint": "R→3 is wrong. The radius of circular path is r = mv/(qB), not v = E/B. The condition v = E/B applies to velocity selectors.", "misconception": "Confusing the radius formula with the velocity selector condition"}, {"option_key": "D", "hint": "P→2 is wrong. The SI unit of magnetic field is Tesla (4), not 2 × 10⁻⁷ N/m (which is the force per unit length between parallel conductors).", "misconception": "Confusing the unit of B with the force value used in defining the ampere"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The direction of force on a current-carrying conductor placed in a magnetic field can be determined using Fleming''s left-hand rule.", "explanation": "This statement is TRUE. Fleming''s left-hand rule states: if the forefinger points in the direction of the magnetic field (B), the middle finger points in the direction of current (I), then the thumb gives the direction of force (F) on the conductor. This rule is specifically used for determining the direction of force on a current-carrying conductor in a magnetic field (motor rule).", "correct_answer": "A", "concept_tags": ["flemings-left-hand-rule", "direction-of-force", "current-carrying-conductor"], "payload": {"question_id": "cuet-phy-magmov-force-17", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Fleming''s left-hand rule is the standard rule for finding the direction of force on a current-carrying conductor in a magnetic field. It is widely used and correct.", "misconception": "Confusing Fleming''s left-hand rule (motor rule) with Fleming''s right-hand rule (generator/dynamo rule)"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A magnetic field can change the speed of a charged particle moving through it.", "explanation": "This statement is FALSE. The magnetic force on a charged particle is F = qv × B, which is always perpendicular to the velocity. A perpendicular force changes only the direction of velocity, not its magnitude (speed). Since no work is done by the magnetic force (W = F · ds = 0 when F ⊥ ds), the kinetic energy and hence the speed remain constant.", "correct_answer": "B", "concept_tags": ["magnetic-force", "speed-constant", "no-work", "perpendicular-force"], "payload": {"question_id": "cuet-phy-magmov-force-18", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic force is always perpendicular to velocity and does zero work. Since work-energy theorem gives ΔKE = W = 0, speed cannot change.", "misconception": "Assuming any force acting on a particle changes its speed"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "One ampere is defined as that steady current which, when flowing through each of two infinitely long, straight, parallel conductors placed 1 m apart in vacuum, produces a force per unit length of _____ N/m between them.", "explanation": "The SI definition of one ampere is based on the force between two parallel current-carrying conductors. Using F/L = μ₀I₁I₂/(2πd), with I₁ = I₂ = 1 A and d = 1 m: F/L = (4π × 10⁻⁷ × 1 × 1)/(2π × 1) = 2 × 10⁻⁷ N/m. This value defines the ampere in the SI system.", "correct_answer": "D", "concept_tags": ["ampere-definition", "parallel-conductors", "force-per-unit-length", "SI-units"], "payload": {"question_id": "cuet-phy-magmov-force-19", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "remember", "options": [{"key": "A", "text": "4π × 10⁻⁷", "is_correct": false}, {"key": "B", "text": "1 × 10⁻⁷", "is_correct": false}, {"key": "C", "text": "4 × 10⁻⁷", "is_correct": false}, {"key": "D", "text": "2 × 10⁻⁷", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4π × 10⁻⁷ is the value of μ₀ (permeability of free space), not the force per unit length. F/L = μ₀I₁I₂/(2πd) = μ₀/(2π) = 2 × 10⁻⁷ N/m.", "misconception": "Confusing μ₀ with the force per unit length"}, {"option_key": "B", "hint": "1 × 10⁻⁷ is half the correct value. The calculation gives μ₀/(2π) = 4π × 10⁻⁷/(2π) = 2 × 10⁻⁷, not 1 × 10⁻⁷.", "misconception": "Arithmetic error in simplifying μ₀/(2π)"}, {"option_key": "C", "hint": "4 × 10⁻⁷ is twice the correct value. Carefully simplify: 4π × 10⁻⁷/(2π) = 2 × 10⁻⁷.", "misconception": "Cancellation error when dividing 4π by 2π"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a mass spectrometer, singly ionized ions of two isotopes of an element (masses m₁ = 20 u and m₂ = 22 u, where 1 u = 1.66 × 10⁻²⁷ kg) are accelerated through a potential difference of 10 kV and then enter a uniform magnetic field of 0.2 T perpendicular to their velocity. The ions travel in semicircular paths and strike a photographic plate. What is the separation between the two lines formed on the photographic plate?", "explanation": "After acceleration, KE = qV, so v = √(2qV/m). The radius of the semicircular path is r = mv/(qB) = (m/(qB))√(2qV/m) = √(2mV/q)/B. The separation on the plate equals the difference in diameters: Δx = 2r₂ − 2r₁ = (2/B)√(2V/q)(√m₂ − √m₁). With q = 1.6 × 10⁻¹⁹ C, V = 10⁴ V, B = 0.2 T: √(2V/q) = √(2 × 10⁴/(1.6 × 10⁻¹⁹)) = √(1.25 × 10²³) = 1.118 × 10¹¹·⁵. Computing: r = √(2mV/q)/B. For m₁ = 20 × 1.66 × 10⁻²⁷ = 3.32 × 10⁻²⁶ kg: r₁ = √(2 × 3.32 × 10⁻²⁶ × 10⁴/1.6 × 10⁻¹⁹)/0.2 = √(4.15 × 10⁻³)/0.2 = 0.0644/0.2 = 0.322 m. For m₂ = 22 × 1.66 × 10⁻²⁷ = 3.652 × 10⁻²⁶ kg: r₂ = √(2 × 3.652 × 10⁻²⁶ × 10⁴/1.6 × 10⁻¹⁹)/0.2 = √(4.565 × 10⁻³)/0.2 = 0.0676/0.2 = 0.338 m. Separation = 2(r₂ − r₁) = 2(0.338 − 0.322) = 2 × 0.016 = 0.032 m ≈ 3.2 cm.", "correct_answer": "B", "concept_tags": ["mass-spectrometer", "isotopes", "semicircular-path", "separation", "scenario-based"], "payload": {"question_id": "cuet-phy-magmov-force-20", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "apply", "options": [{"key": "A", "text": "1.6 cm", "is_correct": false}, {"key": "B", "text": "3.2 cm", "is_correct": true}, {"key": "C", "text": "6.4 cm", "is_correct": false}, {"key": "D", "text": "0.8 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.6 cm is the difference in radii (r₂ − r₁), not diameters. The separation on the photographic plate equals the difference in diameters: 2(r₂ − r₁).", "misconception": "Forgetting to multiply the radius difference by 2 for the diameter difference"}, {"option_key": "C", "hint": "6.4 cm is double the correct answer. Check that you are not multiplying by 4 instead of 2 when converting from radius to diameter difference.", "misconception": "Doubling the diameter difference instead of the radius difference"}, {"option_key": "D", "hint": "0.8 cm is too small. This may result from an error in the calculation of radii or forgetting to use the correct mass values.", "misconception": "Arithmetic error in computing the radii"}]}}]'::jsonb, 'deploy-2026-03-05-b13');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnifying power of a simple microscope is given by:", "explanation": "A simple microscope (magnifying glass) is a convex lens of short focal length. Its magnifying power when the final image is at the least distance of distinct vision (D = 25 cm) is M = 1 + D/f. This formula assumes the image is formed at the near point.", "correct_answer": "B", "concept_tags": ["simple-microscope", "magnifying-power", "convex-lens"], "payload": {"question_id": "cuet-phy-ray-instruments-01", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "M = D/f", "is_correct": false}, {"key": "B", "text": "M = 1 + D/f", "is_correct": true}, {"key": "C", "text": "M = f/D", "is_correct": false}, {"key": "D", "text": "M = 1 + f/D", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "M = D/f gives the magnifying power when the image is at infinity (relaxed eye), not at the near point.", "misconception": "Confusing the formula for image at infinity with image at near point"}, {"option_key": "C", "hint": "M = f/D would give a value less than 1 for typical lenses (f < D), which contradicts the purpose of magnification.", "misconception": "Inverting the D/f ratio"}, {"option_key": "D", "hint": "M = 1 + f/D incorrectly swaps f and D. The correct formula has D in the numerator since D > f for useful magnification.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The near point of a normal human eye is at a distance of:", "explanation": "The near point (least distance of distinct vision) of a normal healthy eye is 25 cm. This is the closest distance at which the eye can focus on an object comfortably. The far point of a normal eye is at infinity.", "correct_answer": "C", "concept_tags": ["near-point", "human-eye", "least-distance-of-distinct-vision"], "payload": {"question_id": "cuet-phy-ray-instruments-02", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "10 cm", "is_correct": false}, {"key": "B", "text": "15 cm", "is_correct": false}, {"key": "C", "text": "25 cm", "is_correct": true}, {"key": "D", "text": "50 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 cm is too close for the normal eye to focus. A person who can see clearly at 10 cm would have an abnormally high accommodation.", "misconception": null}, {"option_key": "B", "hint": "15 cm is less than the standard near point of 25 cm for a normal eye.", "misconception": null}, {"option_key": "D", "hint": "50 cm would be the near point of a person with presbyopia or hypermetropia, not a normal eye.", "misconception": "Confusing normal near point with that of a defective eye"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Myopia (short-sightedness) can be corrected by using a:", "explanation": "In myopia, the eye can see near objects clearly but distant objects appear blurred because the image is formed in front of the retina. A concave (diverging) lens of appropriate focal length diverges the incoming rays before they enter the eye, so the image shifts back to the retina.", "correct_answer": "A", "concept_tags": ["myopia", "concave-lens", "defects-of-vision", "correction"], "payload": {"question_id": "cuet-phy-ray-instruments-03", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "Concave lens", "is_correct": true}, {"key": "B", "text": "Convex lens", "is_correct": false}, {"key": "C", "text": "Cylindrical lens", "is_correct": false}, {"key": "D", "text": "Bifocal lens", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A convex lens converges light further, which would worsen myopia. Convex lenses are used to correct hypermetropia.", "misconception": "Confusing the corrective lens for myopia and hypermetropia"}, {"option_key": "C", "hint": "Cylindrical lenses are used to correct astigmatism, not myopia.", "misconception": "Confusing correction for astigmatism with myopia"}, {"option_key": "D", "hint": "Bifocal lenses are used for presbyopia, where both near and far vision need correction, not for simple myopia.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of power of a lens is:", "explanation": "The power of a lens is defined as P = 1/f, where f is the focal length in metres. The SI unit of lens power is the dioptre (D), where 1 D = 1 m⁻¹.", "correct_answer": "D", "concept_tags": ["power-of-lens", "dioptre", "SI-unit"], "payload": {"question_id": "cuet-phy-ray-instruments-04", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "Metre", "is_correct": false}, {"key": "B", "text": "Watt", "is_correct": false}, {"key": "C", "text": "Centimetre", "is_correct": false}, {"key": "D", "text": "Dioptre", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Metre is the unit of focal length, not power. Power is the reciprocal of focal length.", "misconception": "Confusing focal length unit with power unit"}, {"option_key": "B", "hint": "Watt is the unit of power in mechanics/electricity (energy per unit time), not optical power.", "misconception": "Confusing optical power with mechanical/electrical power"}, {"option_key": "C", "hint": "Centimetre is a unit of length and is not used as the unit of lens power.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnifying power of an astronomical telescope in normal adjustment is 20. If the focal length of the objective is 100 cm, the focal length of the eyepiece is:", "explanation": "For an astronomical telescope in normal adjustment (image at infinity), the magnifying power M = fₒ/fₑ. Given M = 20 and fₒ = 100 cm: 20 = 100/fₑ, so fₑ = 100/20 = 5 cm.", "correct_answer": "B", "concept_tags": ["astronomical-telescope", "magnifying-power", "focal-length"], "payload": {"question_id": "cuet-phy-ray-instruments-05", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "2 cm", "is_correct": false}, {"key": "B", "text": "5 cm", "is_correct": true}, {"key": "C", "text": "10 cm", "is_correct": false}, {"key": "D", "text": "20 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "fₑ = 2 cm would give M = 100/2 = 50, not 20.", "misconception": null}, {"option_key": "C", "hint": "fₑ = 10 cm would give M = 100/10 = 10, not 20.", "misconception": null}, {"option_key": "D", "hint": "fₑ = 20 cm would give M = 100/20 = 5, not 20. Do not confuse the magnification value with the focal length.", "misconception": "Confusing the magnifying power value with the eyepiece focal length"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A compound microscope consists of an objective of focal length 1 cm and an eyepiece of focal length 5 cm. If the length of the tube is 20 cm and the image is formed at the least distance of distinct vision (25 cm), the magnifying power is approximately:", "explanation": "For a compound microscope, M = (L/fₒ) × (1 + D/fₑ), where L is the image distance from the objective (approximately the tube length minus fₑ for rough calculation). More precisely, L ≈ 20 − 5 = 15 cm (separation between objective image and eyepiece). So M = (15/1) × (1 + 25/5) = 15 × 6 = 90. The magnifying power is approximately 90.", "correct_answer": "C", "concept_tags": ["compound-microscope", "magnifying-power", "objective", "eyepiece"], "payload": {"question_id": "cuet-phy-ray-instruments-06", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "30", "is_correct": false}, {"key": "B", "text": "60", "is_correct": false}, {"key": "C", "text": "90", "is_correct": true}, {"key": "D", "text": "120", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "30 would result from using M = L/fₒ × D/fₑ without the +1 term and with incorrect L.", "misconception": null}, {"option_key": "B", "hint": "60 results from using L = 20 cm directly instead of subtracting fₑ to get the image distance from the objective.", "misconception": "Using total tube length instead of image distance from objective"}, {"option_key": "D", "hint": "120 would require L/fₒ = 20, implying L = 20 cm without subtracting fₑ, combined with the full eyepiece magnification.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The length of an astronomical telescope in normal adjustment is 105 cm. If the magnifying power is 20, the focal lengths of the objective and eyepiece are:", "explanation": "In normal adjustment, the tube length L = fₒ + fₑ = 105 cm and M = fₒ/fₑ = 20. From M: fₒ = 20fₑ. Substituting: 20fₑ + fₑ = 105, so 21fₑ = 105, giving fₑ = 5 cm and fₒ = 100 cm.", "correct_answer": "A", "concept_tags": ["astronomical-telescope", "tube-length", "magnifying-power", "focal-length"], "payload": {"question_id": "cuet-phy-ray-instruments-07", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "fₒ = 100 cm, fₑ = 5 cm", "is_correct": true}, {"key": "B", "text": "fₒ = 95 cm, fₑ = 10 cm", "is_correct": false}, {"key": "C", "text": "fₒ = 84 cm, fₑ = 21 cm", "is_correct": false}, {"key": "D", "text": "fₒ = 105 cm, fₑ = 5.25 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "fₒ + fₑ = 95 + 10 = 105 cm (correct sum), but fₒ/fₑ = 95/10 = 9.5, not 20.", "misconception": null}, {"option_key": "C", "hint": "fₒ + fₑ = 84 + 21 = 105 cm (correct sum), but fₒ/fₑ = 84/21 = 4, not 20.", "misconception": null}, {"option_key": "D", "hint": "fₒ + fₑ = 105 + 5.25 = 110.25 cm, which does not equal the tube length of 105 cm.", "misconception": "Ignoring the constraint that fₒ + fₑ = L"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A person with hypermetropia has a near point at 75 cm. The power of the corrective lens required to bring the near point to the normal position (25 cm) is:", "explanation": "The corrective lens must form a virtual image at 75 cm (the defective near point) of an object placed at 25 cm (the normal near point). Using the thin lens formula: 1/f = 1/v − 1/u = 1/(−75) − 1/(−25) = −1/75 + 1/25 = (−1 + 3)/75 = 2/75. So f = 75/2 = 37.5 cm = 0.375 m. Power P = 1/f = 1/0.375 ≈ +2.67 D.", "correct_answer": "D", "concept_tags": ["hypermetropia", "corrective-lens", "power-of-lens", "lens-formula"], "payload": {"question_id": "cuet-phy-ray-instruments-08", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "+1.33 D", "is_correct": false}, {"key": "B", "text": "−2.67 D", "is_correct": false}, {"key": "C", "text": "+4.0 D", "is_correct": false}, {"key": "D", "text": "+2.67 D", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "+1.33 D corresponds to f = 75 cm, which would result from using P = 1/v only, without applying the full lens formula.", "misconception": null}, {"option_key": "B", "hint": "A negative power (concave lens) would further diverge light, making hypermetropia worse. Correction requires a converging (positive) lens.", "misconception": "Using a concave lens for hypermetropia"}, {"option_key": "C", "hint": "+4.0 D corresponds to f = 25 cm. This would result from using only the object distance, ignoring the image distance constraint.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A convex lens of focal length 10 cm is used as a magnifying glass. The maximum magnifying power when the image is formed at the least distance of distinct vision is:", "explanation": "The magnifying power of a simple microscope with the image at the near point is M = 1 + D/f = 1 + 25/10 = 1 + 2.5 = 3.5. This is the maximum magnifying power achievable with this lens.", "correct_answer": "C", "concept_tags": ["simple-microscope", "magnifying-power", "near-point"], "payload": {"question_id": "cuet-phy-ray-instruments-09", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "2.5", "is_correct": false}, {"key": "B", "text": "3.0", "is_correct": false}, {"key": "C", "text": "3.5", "is_correct": true}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "2.5 = D/f, which is the magnifying power when the image is at infinity, not at the near point.", "misconception": "Using M = D/f instead of M = 1 + D/f for near point image"}, {"option_key": "B", "hint": "3.0 does not correspond to any standard formula for this configuration.", "misconception": null}, {"option_key": "D", "hint": "10 is the focal length in cm, not the magnifying power. M = 1 + D/f, not f itself.", "misconception": "Confusing focal length with magnifying power"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The accommodation of the human eye refers to the ability of the eye to:", "explanation": "Accommodation is the ability of the eye lens to change its focal length by altering its curvature through the action of ciliary muscles. When viewing near objects, the ciliary muscles contract, making the lens thicker and decreasing its focal length. For distant objects, the muscles relax, making the lens thinner and increasing the focal length.", "correct_answer": "B", "concept_tags": ["accommodation", "human-eye", "ciliary-muscles", "focal-length"], "payload": {"question_id": "cuet-phy-ray-instruments-10", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "Change the size of the pupil", "is_correct": false}, {"key": "B", "text": "Adjust the focal length of the eye lens", "is_correct": true}, {"key": "C", "text": "Change the distance between the lens and retina", "is_correct": false}, {"key": "D", "text": "Change the refractive index of the eye lens", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Changing pupil size controls the amount of light entering the eye (like an aperture), not the focusing ability.", "misconception": "Confusing pupil adjustment with accommodation"}, {"option_key": "C", "hint": "In the human eye, the distance between the lens and retina is fixed. The eye focuses by changing the lens curvature, not by moving the lens.", "misconception": "Applying camera focusing mechanism to the human eye"}, {"option_key": "D", "hint": "The refractive index of the eye lens material does not change during accommodation; only its curvature changes.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A Galilean telescope has an objective of focal length 30 cm and an eyepiece of focal length 6 cm. For a normal adjustment, the magnifying power and the length of the telescope are:", "explanation": "A Galilean telescope uses a concave lens as the eyepiece. The magnifying power M = fₒ/fₑ = 30/6 = 5. The length of the telescope in normal adjustment is L = fₒ − fₑ = 30 − 6 = 24 cm (since the eyepiece is a diverging lens placed inside the focal point of the objective).", "correct_answer": "D", "concept_tags": ["galilean-telescope", "magnifying-power", "tube-length", "concave-eyepiece"], "payload": {"question_id": "cuet-phy-ray-instruments-11", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "analyze", "options": [{"key": "A", "text": "M = 5, L = 36 cm", "is_correct": false}, {"key": "B", "text": "M = 6, L = 24 cm", "is_correct": false}, {"key": "C", "text": "M = 5, L = 30 cm", "is_correct": false}, {"key": "D", "text": "M = 5, L = 24 cm", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "L = 36 cm = fₒ + fₑ is the tube length for an astronomical telescope (with a convex eyepiece), not a Galilean telescope.", "misconception": "Using L = fₒ + fₑ for a Galilean telescope instead of L = fₒ − fₑ"}, {"option_key": "B", "hint": "M = 6 would require fₒ/fₑ = 6, but 30/6 = 5, not 6.", "misconception": null}, {"option_key": "C", "hint": "L = 30 cm equals fₒ alone. The tube length of a Galilean telescope is fₒ − fₑ, not just fₒ.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A reflecting telescope uses a concave mirror of focal length 100 cm as its objective. If the magnifying power is 50 and the final image is at infinity, the focal length of the eyepiece is:", "explanation": "For a reflecting telescope with the final image at infinity, the magnifying power M = fₒ/fₑ, same as for a refracting telescope. Given M = 50 and fₒ = 100 cm: fₑ = fₒ/M = 100/50 = 2 cm.", "correct_answer": "A", "concept_tags": ["reflecting-telescope", "magnifying-power", "concave-mirror", "eyepiece"], "payload": {"question_id": "cuet-phy-ray-instruments-12", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "analyze", "options": [{"key": "A", "text": "2 cm", "is_correct": true}, {"key": "B", "text": "5 cm", "is_correct": false}, {"key": "C", "text": "50 cm", "is_correct": false}, {"key": "D", "text": "0.5 cm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "fₑ = 5 cm gives M = 100/5 = 20, not 50.", "misconception": null}, {"option_key": "C", "hint": "fₑ = 50 cm gives M = 100/50 = 2, not 50. This confuses the magnification value with the focal length.", "misconception": "Confusing magnifying power with eyepiece focal length"}, {"option_key": "D", "hint": "fₑ = 0.5 cm gives M = 100/0.5 = 200, which is much larger than 50.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): In an astronomical telescope, the objective has a large focal length and the eyepiece has a small focal length.\nReason (R): The magnifying power of an astronomical telescope in normal adjustment is M = fₒ/fₑ.", "explanation": "Both A and R are correct. The magnifying power M = fₒ/fₑ shows that to achieve high magnification, fₒ should be large and fₑ should be small. The reason directly explains why the objective has a large focal length and the eyepiece a small one, so R is the correct explanation of A.", "correct_answer": "A", "concept_tags": ["astronomical-telescope", "magnifying-power", "objective", "eyepiece"], "payload": {"question_id": "cuet-phy-ray-instruments-13", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: the formula M = fₒ/fₑ shows that large fₒ and small fₑ maximise magnification.", "misconception": null}, {"option_key": "C", "hint": "R is the standard and correct formula for the magnifying power of an astronomical telescope in normal adjustment.", "misconception": null}, {"option_key": "D", "hint": "A is correct; any standard astronomical telescope is designed with a long focal length objective and a short focal length eyepiece.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A reflecting telescope is preferred over a refracting telescope for large aperture instruments.\nReason (R): Large lenses suffer from chromatic aberration and are difficult to manufacture without sagging, whereas large mirrors do not have chromatic aberration and can be supported from behind.", "explanation": "Both A and R are correct, and R is the correct explanation of A. Large aperture refracting telescopes suffer from chromatic aberration (since lenses disperse light) and mechanical issues like sagging due to gravity. Reflecting telescopes use mirrors, which have no chromatic aberration and can be supported from behind to prevent sagging. These are the primary reasons why reflecting telescopes are preferred for large instruments.", "correct_answer": "A", "concept_tags": ["reflecting-telescope", "refracting-telescope", "chromatic-aberration", "advantages"], "payload": {"question_id": "cuet-phy-ray-instruments-14", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly addresses the advantages of mirrors over lenses for large apertures, which is exactly why reflecting telescopes are preferred. R explains A.", "misconception": null}, {"option_key": "C", "hint": "R is factually correct — large lenses do suffer from chromatic aberration and sagging, and mirrors avoid both issues.", "misconception": null}, {"option_key": "D", "hint": "A is correct; all major astronomical observatories use reflecting telescopes for their large instruments.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the eye defects in Column I with their corrective lenses in Column II:\n\nColumn I:\nA. Myopia\nB. Hypermetropia\nC. Astigmatism\nD. Presbyopia\n\nColumn II:\n1. Bifocal lens\n2. Cylindrical lens\n3. Concave lens\n4. Convex lens", "explanation": "Myopia is corrected using a concave lens to diverge light (A-3). Hypermetropia is corrected using a convex lens to converge light (B-4). Astigmatism, caused by a non-spherical cornea, is corrected using a cylindrical lens (C-2). Presbyopia, affecting both near and far vision in old age, is corrected using bifocal lenses (D-1).", "correct_answer": "B", "concept_tags": ["myopia", "hypermetropia", "astigmatism", "presbyopia", "corrective-lens"], "payload": {"question_id": "cuet-phy-ray-instruments-15", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "understand", "options": [{"key": "A", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "B", "text": "A-3, B-4, C-2, D-1", "is_correct": true}, {"key": "C", "text": "A-3, B-4, C-1, D-2", "is_correct": false}, {"key": "D", "text": "A-2, B-1, C-3, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps the corrective lenses for myopia and hypermetropia. Myopia requires a concave (diverging) lens, not convex.", "misconception": "Interchanging corrective lenses for myopia and hypermetropia"}, {"option_key": "C", "hint": "This swaps astigmatism and presbyopia corrections. Astigmatism uses cylindrical lenses (2), not bifocal (1).", "misconception": null}, {"option_key": "D", "hint": "This assigns completely incorrect lenses to all defects and has no basis in optics.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the optical instruments in Column I with the correct expression for their magnifying power in Column II:\n\nColumn I:\nA. Simple microscope (image at near point)\nB. Astronomical telescope (normal adjustment)\nC. Compound microscope (image at infinity)\nD. Galilean telescope (normal adjustment)\n\nColumn II:\n1. fₒ/fₑ\n2. (L/fₒ)(D/fₑ)\n3. 1 + D/f\n4. fₒ/fₑ (erect image)", "explanation": "A simple microscope with image at the near point has M = 1 + D/f (A-3). An astronomical telescope in normal adjustment has M = fₒ/fₑ (B-1). A compound microscope with image at infinity has M = (L/fₒ)(D/fₑ) where L is the tube length (C-2). A Galilean telescope in normal adjustment also has M = fₒ/fₑ but produces an erect image (D-4).", "correct_answer": "C", "concept_tags": ["magnifying-power", "simple-microscope", "compound-microscope", "astronomical-telescope", "galilean-telescope"], "payload": {"question_id": "cuet-phy-ray-instruments-16", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-4, C-2, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "C", "text": "A-3, B-1, C-2, D-4", "is_correct": true}, {"key": "D", "text": "A-1, B-3, C-4, D-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and D. The astronomical telescope (B) matches fₒ/fₑ (1), while the Galilean telescope (D) matches fₒ/fₑ with erect image (4).", "misconception": null}, {"option_key": "B", "hint": "A-2 assigns the compound microscope formula to the simple microscope, which is incorrect. The simple microscope uses M = 1 + D/f.", "misconception": "Confusing simple and compound microscope formulas"}, {"option_key": "D", "hint": "This assigns completely incorrect formulas to all instruments. The simple microscope does not use M = fₒ/fₑ.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnifying power of an astronomical telescope increases if the focal length of the objective is increased.", "explanation": "This statement is true. The magnifying power of an astronomical telescope in normal adjustment is M = fₒ/fₑ. If fₒ (focal length of the objective) increases while fₑ remains constant, the magnifying power increases proportionally.", "correct_answer": "A", "concept_tags": ["astronomical-telescope", "magnifying-power", "focal-length"], "payload": {"question_id": "cuet-phy-ray-instruments-17", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Since M = fₒ/fₑ, increasing fₒ directly increases M. The statement is therefore true.", "misconception": "Thinking magnifying power decreases with larger objective focal length"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A person suffering from myopia can see distant objects clearly without any corrective lens.", "explanation": "This statement is false. Myopia (short-sightedness) means the person can see nearby objects clearly but distant objects appear blurred. The far point of a myopic eye is at a finite distance (not at infinity). A concave lens is needed to see distant objects clearly.", "correct_answer": "B", "concept_tags": ["myopia", "defects-of-vision", "far-point"], "payload": {"question_id": "cuet-phy-ray-instruments-18", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Myopia specifically means inability to see distant objects clearly. The image of distant objects falls in front of the retina.", "misconception": "Confusing myopia with normal vision or hypermetropia"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The power of a concave lens of focal length 50 cm is _____ dioptre.", "explanation": "The power of a lens is P = 1/f, where f is in metres. For a concave (diverging) lens, the focal length is negative: f = −50 cm = −0.50 m. Therefore P = 1/(−0.50) = −2 D. The negative sign indicates a diverging lens.", "correct_answer": "B", "concept_tags": ["power-of-lens", "concave-lens", "dioptre", "focal-length"], "payload": {"question_id": "cuet-phy-ray-instruments-19", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "+2", "is_correct": false}, {"key": "B", "text": "−2", "is_correct": true}, {"key": "C", "text": "−0.5", "is_correct": false}, {"key": "D", "text": "+50", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "+2 D would be the power of a convex lens of focal length 50 cm. A concave lens has negative power.", "misconception": "Ignoring the sign convention for concave lens power"}, {"option_key": "C", "hint": "−0.5 would result from using P = −f (in metres) instead of P = 1/f.", "misconception": "Confusing focal length with power"}, {"option_key": "D", "hint": "+50 results from not converting cm to metres and ignoring the sign. P = 1/f where f must be in metres.", "misconception": "Forgetting to convert cm to metres and ignoring sign"}]}}, {"chapter_id": "cuet-phy-optics", "topic_id": "cuet-phy-opt-instruments", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A biology student uses a compound microscope to observe a cell. The objective lens has a focal length of 0.5 cm and the eyepiece has a focal length of 6.25 cm. The object is placed at a distance of 0.55 cm from the objective. The final image is formed at the least distance of distinct vision (25 cm).\n\nWhat is the approximate magnifying power of the microscope?", "explanation": "First, find the image formed by the objective using 1/v − 1/u = 1/f: 1/v = 1/fₒ + 1/uₒ = 1/0.5 + 1/(−0.55) = 2 − 1.818 = 0.182, so v ≈ 5.5 cm. Magnification by objective: mₒ = v/u = 5.5/(−0.55) = −10. Magnification by eyepiece: mₑ = 1 + D/fₑ = 1 + 25/6.25 = 1 + 4 = 5. Total magnifying power M = mₒ × mₑ = −10 × 5 = −50. The magnitude is 50.", "correct_answer": "D", "concept_tags": ["compound-microscope", "magnifying-power", "objective", "eyepiece", "lens-formula"], "payload": {"question_id": "cuet-phy-ray-instruments-20", "subtopic": "Optical Instruments", "topic_name": "Optical Instruments", "bloom_level": "apply", "options": [{"key": "A", "text": "10", "is_correct": false}, {"key": "B", "text": "25", "is_correct": false}, {"key": "C", "text": "40", "is_correct": false}, {"key": "D", "text": "50", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10 is only the magnification produced by the objective alone. The total magnification includes the eyepiece contribution as well.", "misconception": "Ignoring the eyepiece magnification"}, {"option_key": "B", "hint": "25 does not correspond to any meaningful calculation. The eyepiece magnification alone is 5, not 25.", "misconception": null}, {"option_key": "C", "hint": "40 would result from using mₑ = D/fₑ = 4 instead of mₑ = 1 + D/fₑ = 5, missing the +1 term.", "misconception": "Using M = D/fₑ instead of M = 1 + D/fₑ for near-point image"}]}}]'::jsonb, 'deploy-2026-03-05-b13');

